import pg from "pg";
import crypto from "crypto";
const Pool = pg.Pool;
const pool = new Pool({ connectionString: process.env.PROD_DATABASE_URL || process.env.DATABASE_URL });
function hash(s: string): string { return crypto.createHash("md5").update(s.toLowerCase().trim()).digest("hex"); }

interface Q {
  tier: string; exam: string; stem: string; options: string[];
  correct: number; rationale: string; diff: number; bs: string;
  topic: string; subtopic: string; tags: string[]; clinicalPearl: string;
}

function q(bs: string, d: number, s: string, o: string[], c: number, r: string, topic: string, subtopic: string, tags: string[], pearl: string): Q {
  return { tier: "rn", exam: "NCLEX-RN", stem: s, options: o, correct: c, rationale: r, diff: d, bs, topic, subtopic, tags, clinicalPearl: pearl };
}

const QS: Q[] = [
  // ============================================================
  // MEDICAL-SURGICAL: CARDIAC (50 questions)
  // ============================================================
  q("Cardiovascular", 3, "A nurse is caring for a client who develops ST-segment elevation in leads II, III, and aVF on a 12-lead ECG. Which coronary artery is most likely occluded?", ["Left anterior descending artery", "Left circumflex artery", "Right coronary artery", "Left main coronary artery"], 2, "ST elevation in leads II, III, and aVF indicates an inferior wall myocardial infarction, which is most commonly caused by occlusion of the right coronary artery (RCA). The RCA supplies the inferior wall of the heart, the SA node, and the AV node. Option A (LAD) causes anterior wall MI (V1-V4). Option B (LCx) causes lateral wall MI (I, aVL, V5-V6). Option D (left main) would cause extensive ST changes.", "Acute Coronary Syndrome", "Inferior Wall MI", ["cardiac", "ecg", "STEMI", "coronary-anatomy"], "Inferior MI = RCA. Watch for bradycardia and heart block because the RCA supplies the SA and AV nodes."),

  q("Cardiovascular", 2, "A client with atrial fibrillation has a CHA2DS2-VASc score of 4. The nurse anticipates which medication will be prescribed?", ["Aspirin 81 mg daily", "Direct oral anticoagulant such as apixaban", "Clopidogrel alone", "No anticoagulation needed"], 1, "A CHA2DS2-VASc score >= 2 in males or >= 3 in females indicates high stroke risk and requires anticoagulation. Direct oral anticoagulants (DOACs) such as apixaban, rivarelbaan, or dabigatran are preferred over warfarin due to predictable pharmacokinetics and no INR monitoring requirement. Option A (aspirin) is insufficient for high-risk scores. Option C (clopidogrel) is an antiplatelet, not anticoagulant. Option D is incorrect given the high score.", "Atrial Fibrillation", "Stroke Prevention", ["cardiac", "anticoagulation", "atrial-fibrillation", "pharmacology"], "CHA2DS2-VASc >= 2 = anticoagulate. DOACs are first-line over warfarin for non-valvular AFib."),

  q("Cardiovascular", 4, "A client with an acute anterior wall MI suddenly develops a new holosystolic murmur at the apex with hemodynamic instability. The nurse suspects:", ["Aortic stenosis progression", "Acute mitral regurgitation from papillary muscle rupture", "Ventricular septal defect", "Pericardial friction rub"], 1, "A new holosystolic murmur at the apex following anterior MI suggests acute mitral regurgitation due to papillary muscle rupture or dysfunction. This is a mechanical complication requiring emergent surgical intervention. Option A (aortic stenosis) produces a crescendo-decrescendo systolic murmur at the right upper sternal border. Option C (VSD) causes a holosystolic murmur at the left sternal border, not apex. Option D (friction rub) is not a murmur.", "Acute Coronary Syndrome", "Mechanical Complications", ["cardiac", "MI-complications", "murmur", "emergency"], "New murmur after MI = mechanical complication. Apex murmur = mitral regurgitation. Sternal border murmur = VSD. Both are surgical emergencies."),

  q("Cardiovascular", 2, "A nurse is teaching a client about modifiable risk factors for coronary artery disease. Which factor listed is NOT modifiable?", ["Hypertension", "Family history of heart disease", "Hyperlipidemia", "Tobacco use"], 1, "Family history of heart disease is a non-modifiable risk factor for CAD. Non-modifiable risk factors include age (males >45, females >55), gender, race, and family history. Options A (hypertension), C (hyperlipidemia), and D (tobacco use) are all modifiable through lifestyle changes and medication.", "Coronary Artery Disease", "Risk Factors", ["cardiac", "risk-factors", "patient-education", "prevention"], "Non-modifiable CAD risk factors: Age, Gender, Race, Family history. Everything else can be changed."),

  q("Cardiovascular", 3, "A client with heart failure is prescribed carvedilol. The nurse should hold the medication and notify the provider if the client's heart rate is:", ["72 bpm", "64 bpm", "Below 55 bpm with dizziness and fatigue", "80 bpm"], 2, "Beta-blockers like carvedilol reduce heart rate and contractility. A heart rate below 55-60 bpm with symptoms (dizziness, fatigue, syncope) warrants holding the medication and notifying the provider. Asymptomatic bradycardia may be acceptable. Options A, B, and D are heart rates within acceptable ranges for beta-blocker therapy.", "Heart Failure", "Beta-Blocker Therapy", ["cardiac", "heart-failure", "pharmacology", "beta-blockers"], "Hold beta-blockers if HR < 55-60 with symptoms. Always assess both the number AND the patient's symptoms before withholding."),

  q("Cardiovascular", 4, "A nurse is caring for a client with a temporary transvenous pacemaker. The monitor shows pacemaker spikes without QRS complexes following them. This indicates:", ["Normal pacemaker function", "Failure to capture", "Failure to sense", "Undersensing"], 1, "Pacemaker spikes without subsequent QRS complexes indicate failure to capture — the electrical stimulus is delivered but does not depolarize the myocardium. Causes include lead displacement, increased capture threshold, battery depletion, or wire fracture. The nurse should increase the output (mA), check connections, and notify the provider. Option A is incorrect because capture requires a QRS after each spike. Options C and D (sensing issues) involve inappropriate pacing related to the pacemaker not detecting intrinsic beats.", "Cardiac Pacing", "Pacemaker Malfunction", ["cardiac", "pacemaker", "critical-care", "ecg-interpretation"], "Spike + no QRS = failure to capture. Increase mA. No spike when needed = failure to fire. Spike at wrong time = failure to sense."),

  q("Cardiovascular", 3, "A client is diagnosed with pericarditis. Which position provides the most comfort?", ["Supine with legs elevated", "Sitting up and leaning forward", "Left lateral recumbent", "Prone position"], 1, "Sitting upright and leaning forward reduces pericardial friction and stretching of the inflamed pericardium, providing pain relief. This is a classic finding in pericarditis. Option A (supine) typically worsens pain. Options C and D do not specifically reduce pericardial irritation. Other hallmarks include pleuritic chest pain, friction rub on auscultation, and diffuse ST elevation on ECG.", "Pericarditis", "Symptom Management", ["cardiac", "pericarditis", "positioning", "assessment"], "Pericarditis pain: worse supine, better leaning forward. Listen for friction rub. ECG shows diffuse ST elevation (saddle-shaped)."),

  q("Cardiovascular", 2, "A nurse is monitoring a client on telemetry who develops torsades de pointes. Which electrolyte imbalance is most commonly associated with this dysrhythmia?", ["Hyperkalemia", "Hypomagnesemia", "Hypernatremia", "Hypercalcemia"], 1, "Torsades de pointes is a polymorphic ventricular tachycardia associated with prolonged QT interval. Hypomagnesemia is a common trigger. Treatment includes IV magnesium sulfate 1-2 g, even if serum magnesium is normal. Option A (hyperkalemia) causes peaked T-waves and wide QRS. Options C and D are less commonly associated with torsades.", "Dysrhythmias", "Torsades de Pointes", ["cardiac", "dysrhythmia", "electrolytes", "magnesium"], "Torsades de pointes = give IV magnesium. Always check and correct Mg2+ and K+ in any cardiac dysrhythmia."),

  q("Cardiovascular", 3, "A client 48 hours post-cardiac catheterization via the femoral artery develops sudden onset of pain, pallor, and pulselessness in the affected leg. The nurse suspects:", ["Deep vein thrombosis", "Arterial occlusion from thromboembolism", "Vasovagal response", "Hematoma at the insertion site"], 1, "The 6 P's of acute arterial occlusion: Pain, Pallor, Pulselessness, Paresthesia, Paralysis, Poikilothermia. Following femoral artery catheterization, thrombus formation at the puncture site can embolize and occlude the distal artery. This is a vascular emergency requiring immediate intervention. Option A (DVT) causes swelling and warmth, not pallor and pulselessness. Option C (vasovagal) would cause bradycardia and hypotension. Option D (hematoma) causes local swelling.", "Cardiac Catheterization", "Post-Procedure Complications", ["cardiac", "vascular", "catheterization", "emergency"], "6 P's of arterial occlusion: Pain, Pallor, Pulselessness, Paresthesia, Paralysis, Poikilothermia. Notify vascular surgeon immediately."),

  q("Cardiovascular", 5, "A nurse is caring for a client in cardiogenic shock with a pulmonary artery catheter. The hemodynamic readings show: CI 1.8 L/min/m2, PCWP 24 mmHg, SVR 2100 dynes/sec/cm5. Which intervention should the nurse anticipate?", ["Aggressive IV fluid bolus", "Inotropic support with dobutamine", "Vasopressor therapy with phenylephrine", "Diuretic therapy alone"], 1, "The hemodynamic profile shows low cardiac index (normal 2.5-4.0), elevated PCWP indicating fluid overload (normal 6-12 mmHg), and elevated SVR indicating compensatory vasoconstriction (normal 800-1200). This is classic cardiogenic shock. Dobutamine increases contractility (inotropy) and causes mild vasodilation, improving cardiac output. Option A (fluids) would worsen pulmonary congestion. Option C (phenylephrine) is a pure vasopressor that would increase afterload. Option D (diuretics alone) does not address the pump failure.", "Shock", "Cardiogenic Shock", ["cardiac", "shock", "hemodynamics", "critical-care"], "Cardiogenic shock: High PCWP + Low CI + High SVR. Treat with inotropes (dobutamine), not fluids. Fluids worsen pulmonary edema."),

  q("Cardiovascular", 2, "A client with a prosthetic mechanical heart valve asks why lifelong anticoagulation is necessary. The nurse's best response is:", ["Mechanical valves cause blood to clot more easily throughout the body", "The synthetic valve surface promotes thrombus formation, and anticoagulation prevents embolic stroke", "Anticoagulation prevents valve deterioration", "It is only needed for the first year after surgery"], 1, "Mechanical heart valves have thrombogenic surfaces that activate the clotting cascade. Without anticoagulation, thrombi can form on the valve and embolize to the brain (stroke), lungs, or other organs. Warfarin is the standard anticoagulant for mechanical valves (DOACs are not recommended). Target INR is typically 2.5-3.5. Option A is too vague. Option C is incorrect. Option D is incorrect — it is lifelong.", "Valvular Heart Disease", "Prosthetic Valves", ["cardiac", "valves", "anticoagulation", "patient-education"], "Mechanical valve = lifelong warfarin (INR 2.5-3.5). Bioprosthetic valve = warfarin for 3-6 months only."),

  q("Cardiovascular", 3, "A nurse assesses a client with infective endocarditis. Which finding is characteristic of this condition?", ["Kussmaul respirations", "Osler nodes and Janeway lesions", "Cullen sign", "Trousseau sign"], 1, "Infective endocarditis causes vegetations on heart valves. Peripheral manifestations include Osler nodes (painful, erythematous nodules on fingers/toes from immune complex deposition), Janeway lesions (painless, hemorrhagic lesions on palms/soles), splinter hemorrhages in nails, and Roth spots in retina. Option A is seen in DKA. Option C is seen in pancreatitis. Option D is seen in hypocalcemia.", "Endocarditis", "Clinical Manifestations", ["cardiac", "endocarditis", "assessment", "infectious-disease"], "Endocarditis findings: Osler = OUCH (painful). Janeway = painless. Also: splinter hemorrhages, Roth spots, new murmur, fever."),

  q("Cardiovascular", 3, "A client with peripheral arterial disease reports intermittent claudication. The nurse should advise:", ["Elevate the legs above heart level at all times", "Implement a structured walking program with rest intervals", "Apply compression stockings", "Soak feet in hot water daily"], 1, "Intermittent claudication (leg pain with walking that resolves with rest) is managed with supervised exercise therapy — structured walking programs increase collateral circulation and improve pain-free walking distance. Option A (elevation) reduces arterial flow to legs. Option C (compression) is for venous disease. Option D (hot water) can cause burns in clients with peripheral neuropathy.", "Peripheral Vascular Disease", "Arterial Disease Management", ["vascular", "PAD", "exercise", "patient-education"], "Arterial disease: legs DOWN (dangle for perfusion). Venous disease: legs UP (elevate to reduce edema). Compression = venous only."),

  q("Cardiovascular", 4, "A client with acute decompensated heart failure is receiving IV nitroprusside. The nurse should monitor for which serious adverse effect?", ["Hyperkalemia", "Cyanide toxicity with prolonged infusion", "Hyperglycemia", "Rebound hypertension"], 1, "Nitroprusside is metabolized to cyanide, which can accumulate with prolonged infusion (>48-72 hours) or high doses. Signs of cyanide toxicity include metabolic acidosis, tachycardia, altered mental status, and the classic cherry-red skin color. Treatment is sodium thiosulfate or hydroxocobalamin. Monitor thiocyanate levels if infusion exceeds 72 hours. Options A and C are not associated with nitroprusside. Option D can occur but cyanide toxicity is the most serious.", "Heart Failure", "Vasoactive Medications", ["cardiac", "heart-failure", "critical-care", "pharmacology"], "Nitroprusside: protect from light (wrap in foil), limit infusion to 48-72 hours, monitor for cyanide toxicity (metabolic acidosis, confusion)."),

  q("Cardiovascular", 2, "A nurse is teaching a client about cardiac rehabilitation after an MI. When should the client avoid sexual activity?", ["Permanently after an MI", "Until the client can climb two flights of stairs without symptoms", "Only if the client has a stent placed", "Sexual activity is unrestricted immediately after discharge"], 1, "Cardiac rehabilitation guidelines suggest that sexual activity can be safely resumed when the client can perform moderate exercise equivalent to climbing two flights of stairs (3-4 METs) without chest pain, dyspnea, or significant ST changes. This is typically 4-6 weeks post-MI. Option A is unnecessarily restrictive. Options C and D are incorrect.", "Cardiac Rehabilitation", "Activity Guidelines", ["cardiac", "rehabilitation", "patient-education", "MI-recovery"], "Post-MI sexual activity: safe when client tolerates 3-4 METs (climbing 2 flights of stairs). Usually 4-6 weeks. Use nitroglycerin prophylactically if prescribed."),

  q("Cardiovascular", 3, "A client presents with Beck's triad: hypotension, muffled heart sounds, and jugular venous distension. The nurse recognizes this as:", ["Tension pneumothorax", "Cardiac tamponade", "Acute heart failure", "Pulmonary embolism"], 1, "Beck's triad is the hallmark of cardiac tamponade — fluid accumulates in the pericardial sac, compressing the heart and reducing cardiac output. Treatment is emergent pericardiocentesis. Pulsus paradoxus (>10 mmHg drop in systolic BP during inspiration) is another key finding. Option A (tension pneumothorax) causes tracheal deviation. Option C (heart failure) causes crackles. Option D (PE) causes acute dyspnea and pleuritic chest pain.", "Cardiac Tamponade", "Emergency Recognition", ["cardiac", "tamponade", "emergency", "assessment"], "Beck's triad: Hypotension + Muffled heart sounds + JVD = cardiac tamponade. Pulsus paradoxus confirms. Emergency pericardiocentesis is the treatment."),

  q("Cardiovascular", 3, "A client with an implantable cardioverter-defibrillator (ICD) reports receiving multiple shocks within 30 minutes. The nurse should:", ["Reassure the client that this is normal", "Apply a magnet to the ICD and call 911", "Instruct the client to take a deep breath and cough", "Tell the client to wait and see if shocks continue"], 1, "Multiple ICD shocks (also called ICD storm) within a short period is a medical emergency. Applying a magnet over the ICD temporarily deactivates tachyarrhythmia detection. The client needs emergent evaluation for underlying causes (electrolyte imbalances, ischemia, lead malfunction). Option A minimizes a potentially life-threatening situation. Options C and D delay necessary treatment.", "Cardiac Devices", "ICD Management", ["cardiac", "ICD", "emergency", "patient-education"], "ICD storm (>3 shocks in 24 hours) = medical emergency. Apply magnet to deactivate, call 911. Causes: VT storm, lead fracture, oversensing."),

  q("Cardiovascular", 3, "A nurse is assessing a client post-coronary artery bypass graft (CABG) surgery. Which finding requires immediate intervention?", ["Temperature of 37.8°C on postoperative day 1", "Chest tube output of 200 mL in the first hour", "Mediastinal chest tube output exceeding 200 mL/hour for 2 consecutive hours", "Mild sternal discomfort"], 2, "Excessive mediastinal bleeding (>200 mL/hour for 2+ hours) post-CABG indicates possible surgical bleeding requiring re-exploration. Normal chest tube output decreases progressively. Option A (low-grade fever) is common post-surgery from atelectasis. Option B (200 mL in the first hour) may be within normal limits. Option D (sternal discomfort) is expected after sternotomy.", "Post-Cardiac Surgery", "CABG Complications", ["cardiac", "post-surgical", "chest-tube", "bleeding"], "Post-CABG: Watch for excessive bleeding (>200 mL/hr x 2 hrs), cardiac tamponade, atrial fibrillation (30% incidence), and sternal wound infection."),

  q("Cardiovascular", 2, "A client with a new diagnosis of heart failure asks about dietary sodium restriction. The nurse should teach:", ["Sodium intake should be unlimited as long as diuretics are taken", "Limit sodium to less than 2,000 mg per day and read food labels carefully", "Only restrict sodium if edema develops", "Avoid all salt substitutes"], 1, "The AHA recommends less than 1,500-2,000 mg sodium per day for heart failure patients. Reading food labels, avoiding processed foods, and using herbs/spices instead of salt are key strategies. Option A is incorrect — sodium restriction is essential regardless of diuretics. Option C delays appropriate intervention. Option D — some salt substitutes contain potassium, which may be beneficial but requires monitoring.", "Heart Failure", "Dietary Management", ["cardiac", "heart-failure", "nutrition", "patient-education"], "Heart failure sodium limit: < 2,000 mg/day. Caution with salt substitutes (contain KCl) — monitor potassium especially with ACE inhibitors/ARBs/spironolactone."),

  q("Cardiovascular", 4, "A nurse is caring for a client with an acute STEMI. The door-to-balloon time goal for primary PCI is:", ["Less than 120 minutes", "Less than 90 minutes", "Less than 60 minutes", "Less than 30 minutes"], 1, "Current ACC/AHA guidelines recommend door-to-balloon time of less than 90 minutes for primary percutaneous coronary intervention (PCI) in STEMI patients. This time frame maximizes myocardial salvage and reduces mortality. If PCI is not available within 120 minutes of first medical contact, fibrinolytic therapy should be administered within 30 minutes (door-to-needle). Option A exceeds the recommendation. Options C and D, while ideal, are not the standard guideline targets.", "Acute Coronary Syndrome", "STEMI Management", ["cardiac", "STEMI", "PCI", "time-sensitive"], "STEMI time goals: Door-to-balloon < 90 min (PCI). Door-to-needle < 30 min (fibrinolytics if PCI unavailable within 120 min)."),

  q("Cardiovascular", 3, "A client with aortic stenosis reports syncope with exertion. The nurse understands that syncope in aortic stenosis occurs because:", ["The client is hyperventilating", "Fixed cardiac output cannot increase to meet exercise demands, causing cerebral hypoperfusion", "The aortic valve prolapses during exercise", "Vagal stimulation causes bradycardia"], 1, "In severe aortic stenosis, the narrowed valve orifice limits cardiac output augmentation during exercise. Despite peripheral vasodilation with exercise, the heart cannot increase output, leading to decreased cerebral perfusion and syncope. The classic triad of aortic stenosis is angina, syncope, and heart failure. Option A is unrelated. Option C describes mitral valve prolapse. Option D is not the primary mechanism.", "Valvular Heart Disease", "Aortic Stenosis", ["cardiac", "valves", "syncope", "pathophysiology"], "Aortic stenosis triad: Angina, Syncope, Heart failure (ASH). Syncope with exertion indicates severe stenosis requiring valve replacement."),

  q("Cardiovascular", 3, "A nurse is monitoring a client receiving tissue plasminogen activator (tPA) for acute ischemic stroke. Which assessment finding requires immediate action?", ["Blood pressure 150/90 mmHg", "Mild headache", "Sudden severe headache with vomiting and neurological deterioration", "Slight oozing from the IV site"], 2, "Sudden severe headache with vomiting and neurological deterioration during or after tPA administration strongly suggests hemorrhagic transformation (intracerebral hemorrhage) — the most feared complication. The tPA infusion must be stopped immediately, stat CT obtained, and coagulation labs drawn. Cryoprecipitate and tranexamic acid may be indicated. Option A (BP 150/90) may be acceptable. Option B (mild headache) warrants monitoring. Option D (IV oozing) is expected.", "Stroke", "Thrombolytic Therapy", ["cardiac", "stroke", "tPA", "emergency"], "During tPA: sudden severe headache = hemorrhagic transformation until proven otherwise. STOP tPA immediately, stat CT, check fibrinogen."),

  q("Cardiovascular", 2, "A nurse is assessing a client's ankle-brachial index (ABI). A result of 0.65 indicates:", ["Normal arterial perfusion", "Mild peripheral arterial disease", "Moderate to severe peripheral arterial disease requiring intervention", "Venous insufficiency"], 2, "ABI interpretation: >1.0 = normal; 0.9-1.0 = acceptable; 0.7-0.89 = mild PAD; 0.4-0.69 = moderate to severe PAD; <0.4 = severe PAD with rest pain and tissue loss risk. An ABI of 0.65 indicates moderate to severe disease. Option A (normal) requires ABI >1.0. Option B (mild) would be 0.7-0.89. Option D (venous) is not assessed by ABI.", "Peripheral Vascular Disease", "Ankle-Brachial Index", ["vascular", "PAD", "assessment", "diagnostics"], "ABI interpretation: >1.0 normal, 0.7-0.89 mild PAD, 0.4-0.69 moderate-severe PAD, <0.4 severe/critical limb ischemia."),

  q("Cardiovascular", 3, "A client with heart failure is prescribed sacubitril/valsartan (Entresto). The nurse should ensure that the client has discontinued which medication at least 36 hours prior?", ["Metoprolol", "ACE inhibitors", "Furosemide", "Digoxin"], 1, "Sacubitril/valsartan must not be given within 36 hours of ACE inhibitor use due to the risk of severe angioedema. Sacubitril inhibits neprilysin, which degrades bradykinin. Combined with ACE inhibitor (which also increases bradykinin), there is a synergistic increase in bradykinin leading to life-threatening angioedema. Options A, C, and D can be taken concurrently with Entresto.", "Heart Failure", "Neprilysin Inhibitor Therapy", ["cardiac", "heart-failure", "pharmacology", "drug-interactions"], "Entresto (sacubitril/valsartan): 36-hour ACE inhibitor washout required. Never combine with ACE inhibitors due to angioedema risk."),

  q("Cardiovascular", 3, "A nurse notes that a client on continuous ECG monitoring has a PR interval of 0.28 seconds with consistent 1:1 P-wave to QRS conduction. This finding represents:", ["Normal sinus rhythm", "First-degree AV block", "Second-degree AV block Type I", "Third-degree AV block"], 1, "A PR interval >0.20 seconds with consistent 1:1 conduction (every P wave followed by a QRS) is first-degree AV block. It is usually benign and does not require treatment. Option A (NSR) has PR 0.12-0.20 seconds. Option C (Mobitz Type I) has progressively lengthening PR until a dropped QRS. Option D (third-degree) has no relationship between P waves and QRS complexes.", "Dysrhythmias", "AV Blocks", ["cardiac", "ecg", "dysrhythmia", "AV-block"], "First-degree AV block: PR > 0.20 sec, all P waves conduct. Usually benign. Monitor for progression to higher-degree blocks, especially with digoxin or beta-blocker therapy."),

  q("Cardiovascular", 4, "A client develops ventricular fibrillation during cardiac catheterization. The nurse's immediate action is to:", ["Administer IV amiodarone", "Begin CPR and prepare for defibrillation", "Obtain a 12-lead ECG for confirmation", "Administer IV atropine"], 1, "Ventricular fibrillation is a pulseless, shockable rhythm. Immediate CPR and defibrillation are the priority interventions per ACLS guidelines. Defibrillation is the definitive treatment — survival decreases by 7-10% for every minute defibrillation is delayed. Option A (amiodarone) is given after the first or second shock. Option C delays treatment. Option D (atropine) is for bradycardia, not VFib.", "Cardiac Arrest", "VFib Management", ["cardiac", "ACLS", "defibrillation", "emergency"], "VFib/pulseless VTach: CPR + Defibrillate immediately. Epinephrine after 2nd shock. Amiodarone after 3rd shock. Never delay defibrillation."),

  q("Cardiovascular", 2, "A client with newly diagnosed hypertension asks about lifestyle modifications. Which recommendation should the nurse prioritize?", ["Limit alcohol to 4 drinks per day", "Follow the DASH diet and reduce sodium intake", "Exercise only on weekends for longer duration", "Take OTC cold medications as needed"], 1, "The DASH (Dietary Approaches to Stop Hypertension) diet emphasizes fruits, vegetables, whole grains, and low-fat dairy while limiting sodium to 2,300 mg/day (ideally 1,500 mg). Combined with exercise, weight loss, and alcohol moderation, it can reduce SBP by 8-14 mmHg. Option A — limit to 1-2 drinks/day. Option C — 150 min/week moderate exercise. Option D — many OTC cold meds contain pseudoephedrine which raises BP.", "Hypertension", "Lifestyle Modifications", ["cardiac", "hypertension", "nutrition", "DASH-diet"], "DASH diet can lower SBP by 8-14 mmHg. Combined lifestyle modifications can be as effective as a single antihypertensive medication."),

  // ============================================================
  // MEDICAL-SURGICAL: RESPIRATORY (45 questions)
  // ============================================================
  q("Respiratory", 3, "A nurse is caring for a client with acute respiratory distress syndrome (ARDS) on mechanical ventilation. The physician orders lung-protective ventilation. The nurse should set the tidal volume to:", ["10-12 mL/kg of actual body weight", "6-8 mL/kg of ideal body weight", "15 mL/kg of ideal body weight", "4 mL/kg of actual body weight"], 1, "ARDS lung-protective ventilation (ARDSNet protocol) uses low tidal volumes of 6-8 mL/kg of IDEAL body weight (IBW) to minimize ventilator-induced lung injury (VILI). Using actual body weight can result in excessive tidal volumes in obese patients. Plateau pressure should be maintained below 30 cmH2O. Options A and C use excessive volumes. Option D is too low.", "ARDS", "Mechanical Ventilation", ["respiratory", "ARDS", "ventilation", "critical-care"], "ARDSNet: TV 6-8 mL/kg IBW, plateau pressure < 30 cmH2O, PEEP titration. Calculate IBW using height, not actual weight."),

  q("Respiratory", 2, "A client with COPD is receiving oxygen therapy. The nurse should set the oxygen flow rate to maintain SpO2 at:", ["98-100%", "88-92%", "80-85%", "95-100%"], 1, "COPD patients rely on hypoxic drive for respiratory stimulation. High-flow oxygen can suppress this drive, leading to CO2 retention and respiratory failure. The target SpO2 for COPD patients is 88-92%. Options A and D (high SpO2 targets) risk suppressing the hypoxic drive. Option C (80-85%) is dangerously low.", "COPD", "Oxygen Therapy", ["respiratory", "COPD", "oxygen", "safety"], "COPD oxygen target: SpO2 88-92%. Use Venturi mask for precise FiO2 delivery. Monitor for CO2 narcosis: confusion, somnolence, headache."),

  q("Respiratory", 3, "A client with a tension pneumothorax presents with tracheal deviation to the unaffected side, absent breath sounds on the affected side, and hypotension. The nurse should anticipate:", ["Chest X-ray before any intervention", "Immediate needle decompression followed by chest tube insertion", "Intubation as the first intervention", "Administration of IV antibiotics"], 1, "Tension pneumothorax is a life-threatening emergency requiring immediate decompression. Needle decompression is performed at the 2nd intercostal space, midclavicular line on the affected side, followed by chest tube insertion. Do NOT delay treatment for imaging. Option A delays critical intervention. Option C does not address the underlying problem. Option D is for infection, not pneumothorax.", "Pneumothorax", "Tension Pneumothorax", ["respiratory", "pneumothorax", "emergency", "chest-tube"], "Tension pneumothorax: tracheal deviation AWAY from affected side. Needle decompression at 2nd ICS, MCL. Do NOT wait for CXR."),

  q("Respiratory", 3, "A nurse is caring for a client with status asthmaticus who is not responding to nebulized albuterol. The nurse should anticipate:", ["Discontinuing all bronchodilators", "IV magnesium sulfate and possible intubation", "Oral corticosteroids only", "Discharge with outpatient follow-up"], 1, "Status asthmaticus is a severe, life-threatening asthma exacerbation that does not respond to standard bronchodilator therapy. IV magnesium sulfate (2 g over 20 minutes) is a smooth muscle relaxant that provides additional bronchodilation. If the patient continues to deteriorate (silent chest, rising PaCO2, altered mental status), intubation and mechanical ventilation may be necessary. Option A worsens bronchospasm. Option C is insufficient for status asthmaticus. Option D is inappropriate for a medical emergency.", "Asthma", "Status Asthmaticus", ["respiratory", "asthma", "emergency", "magnesium"], "Status asthmaticus: if albuterol fails, give IV magnesium sulfate 2g. Silent chest = ominous sign (no air movement). Rising PaCO2 = impending respiratory failure."),

  q("Respiratory", 2, "A client has a chest tube connected to water-seal drainage. The nurse observes tidaling in the water-seal chamber. This indicates:", ["An air leak in the system", "Normal functioning of the chest tube", "The lung has fully re-expanded", "The chest tube is obstructed"], 1, "Tidaling (fluctuation of water level in the water-seal chamber with respiration) is a normal finding indicating that the chest tube is patent and properly functioning. The water level rises with inspiration and falls with expiration in spontaneously breathing patients. Absence of tidaling may indicate lung re-expansion, tube occlusion, or kinking. Option A (air leak) causes continuous bubbling. Option C would show absence of tidaling. Option D would also stop tidaling.", "Chest Tube Management", "Water-Seal Assessment", ["respiratory", "chest-tube", "assessment", "drainage"], "Tidaling = normal. Continuous bubbling = air leak. No tidaling = lung re-expanded or tube occlusion. Never clamp a chest tube without a provider order."),

  q("Respiratory", 4, "A nurse is interpreting ABG results: pH 7.28, PaCO2 58 mmHg, HCO3 24 mEq/L, PaO2 60 mmHg. These results indicate:", ["Metabolic acidosis", "Acute respiratory acidosis with hypoxemia", "Compensated respiratory alkalosis", "Mixed acid-base disorder"], 1, "pH < 7.35 = acidosis. PaCO2 > 45 mmHg = respiratory cause. HCO3 is normal (22-26), indicating no metabolic compensation (acute). PaO2 < 80 mmHg confirms hypoxemia. This is acute (uncompensated) respiratory acidosis, likely from hypoventilation. Option A would show low HCO3. Option C would have high pH. Option D would show abnormalities in both PaCO2 and HCO3.", "Acid-Base Balance", "ABG Interpretation", ["respiratory", "ABG", "acid-base", "critical-care"], "ABG steps: 1) pH (acid or alkaline?), 2) PaCO2 (respiratory cause?), 3) HCO3 (metabolic cause?), 4) Compensation? Normal HCO3 with abnormal pH = uncompensated."),

  q("Respiratory", 3, "A client with pulmonary embolism is started on heparin therapy. Which laboratory test should the nurse monitor to assess therapeutic effectiveness?", ["Prothrombin time (PT)", "Activated partial thromboplastin time (aPTT)", "Platelet count only", "Fibrinogen level"], 1, "Heparin therapy is monitored by aPTT (therapeutic range is 1.5-2.5 times control, typically 60-80 seconds). Option A (PT/INR) monitors warfarin therapy. Option C (platelets) is important for detecting HIT but does not measure therapeutic effectiveness. Option D (fibrinogen) is used for DIC monitoring, not heparin effectiveness.", "Pulmonary Embolism", "Anticoagulation Monitoring", ["respiratory", "PE", "heparin", "lab-values"], "Heparin = monitor aPTT (1.5-2.5x control). Warfarin = monitor PT/INR. LMWH (enoxaparin) = monitor anti-Xa levels if needed. Check platelets for HIT."),

  q("Respiratory", 2, "A nurse is teaching a client with newly diagnosed asthma about inhaler technique. The client should be taught to use the rescue inhaler:", ["On a fixed schedule every 4 hours", "At the first sign of symptoms such as wheezing, chest tightness, or dyspnea", "Only at bedtime", "After using the maintenance inhaler"], 1, "Short-acting beta-agonists (SABAs) like albuterol are rescue inhalers used PRN for acute bronchospasm. They provide rapid relief within 5-15 minutes. Using rescue inhalers >2 times per week (excluding exercise-induced use) indicates uncontrolled asthma requiring step-up therapy. Option A describes scheduled medication. Options C and D are incorrect usage patterns.", "Asthma", "Inhaler Education", ["respiratory", "asthma", "inhalers", "patient-education"], "Rescue inhaler (SABA) use >2x/week = uncontrolled asthma. ICS (inhaled corticosteroid) is the cornerstone of asthma maintenance therapy. Rinse mouth after ICS to prevent thrush."),

  q("Respiratory", 3, "A client with pneumonia develops a pleural effusion. The nurse prepares the client for thoracentesis. Which position is optimal?", ["Supine with arms at sides", "Sitting upright leaning forward over a bedside table", "Trendelenburg position", "Right lateral decubitus"], 1, "The sitting-upright-leaning-forward position allows fluid to pool at the base of the lung and maximizes access to the pleural space. This position also separates the intercostal spaces for easier needle insertion. Option A does not optimize fluid positioning. Option C could worsen respiratory distress. Option D may be used if the client cannot sit up.", "Pleural Effusion", "Thoracentesis", ["respiratory", "pleural-effusion", "procedures", "positioning"], "Thoracentesis position: sitting upright, leaning forward. Maximum single drainage: 1,000-1,500 mL to prevent re-expansion pulmonary edema. Monitor for pneumothorax post-procedure."),

  q("Respiratory", 4, "A client on mechanical ventilation develops high peak airway pressures with normal plateau pressures. The nurse should assess for:", ["Pneumothorax or bronchospasm", "Decreased lung compliance", "Acute respiratory distress syndrome", "Pulmonary fibrosis"], 0, "High peak pressures with normal plateau pressures indicate increased airway resistance (the problem is in the airways, not the lungs). Causes include bronchospasm, mucus plugging, kinked endotracheal tube, or water in the ventilator circuit. Option B (decreased compliance) would show high peak AND high plateau pressures. Options C and D also affect compliance, not resistance.", "Mechanical Ventilation", "Troubleshooting", ["respiratory", "ventilation", "critical-care", "airway-pressure"], "High peak + normal plateau = airway resistance (bronchospasm, mucus, kinked tube). High peak + high plateau = poor compliance (ARDS, pneumothorax, pulmonary edema)."),

  q("Respiratory", 3, "A client with tuberculosis is started on the standard four-drug regimen. Which medications are included in the initial intensive phase?", ["Isoniazid, ethambutol, and amoxicillin", "Rifampin, isoniazid, pyrazinamide, and ethambutol", "Isoniazid and rifampin only", "Streptomycin and doxycycline"], 1, "The standard initial intensive phase of TB treatment (first 2 months) uses RIPE: Rifampin, Isoniazid, Pyrazinamide, and Ethambutol. The continuation phase (4-7 months) typically uses Isoniazid and Rifampin. Option A includes a non-TB antibiotic. Option C is the continuation phase only. Option D is not standard first-line therapy.", "Tuberculosis", "Drug Therapy", ["respiratory", "TB", "pharmacology", "infection-control"], "TB RIPE therapy: Rifampin (orange body fluids), Isoniazid (monitor liver, give B6), Pyrazinamide (hepatotoxic), Ethambutol (monitor vision). Intensive phase: 2 months."),

  q("Respiratory", 2, "A nurse is caring for a client with a tracheostomy. Which action is essential during suctioning?", ["Apply continuous suction while inserting the catheter", "Apply suction only during catheter withdrawal, limiting to 10-15 seconds", "Suction for 30 seconds per pass to ensure clearance", "Use the largest catheter available for thorough suctioning"], 1, "Suctioning technique: Insert catheter WITHOUT suction, apply intermittent suction during withdrawal only, limit each pass to 10-15 seconds to prevent hypoxia, hypotension, and vagal stimulation. Catheter size should be no more than half the internal diameter of the tracheostomy tube. Hyperoxygenate with 100% FiO2 before and after suctioning. Option A can cause mucosal trauma. Option C exceeds safe duration. Option D can occlude the airway.", "Tracheostomy Care", "Suctioning Technique", ["respiratory", "tracheostomy", "suctioning", "procedures"], "Suction: no suction during insertion, limit 10-15 seconds per pass, hyperoxygenate before and after, catheter ≤ 1/2 trach tube diameter."),

  q("Respiratory", 3, "A client with severe COPD has a PaCO2 of 55 mmHg at baseline. The nurse understands that this client's primary stimulus for breathing is:", ["High PaCO2 levels stimulating central chemoreceptors", "Low PaO2 levels stimulating peripheral chemoreceptors", "High pH levels", "High bicarbonate levels"], 1, "In chronic CO2 retainers (severe COPD), central chemoreceptors become desensitized to chronically elevated CO2. The respiratory drive shifts to the hypoxic drive — peripheral chemoreceptors in the carotid and aortic bodies respond to low PaO2. This is why excessive oxygen can suppress breathing in COPD patients. Option A is the normal stimulus but is blunted in COPD. Options C and D do not directly stimulate breathing.", "COPD", "Respiratory Drive", ["respiratory", "COPD", "pathophysiology", "oxygen-therapy"], "COPD hypoxic drive: peripheral chemoreceptors (carotid/aortic bodies) respond to low PaO2. High-flow O2 removes this stimulus, causing hypoventilation and CO2 narcosis."),

  q("Respiratory", 3, "A nurse is assessing a client who presents with sudden onset pleuritic chest pain, tachycardia, and hemoptysis after a long flight. The nurse suspects:", ["Spontaneous pneumothorax", "Pulmonary embolism", "Community-acquired pneumonia", "Acute bronchitis"], 1, "The triad of pleuritic chest pain, tachycardia, and hemoptysis after prolonged immobility (long flight) is classic for pulmonary embolism. Risk factors include prolonged immobilization, surgery, hormonal contraceptives, and hypercoagulable states. D-dimer is used for screening; CT pulmonary angiography is the gold standard diagnostic test. Option A typically presents with sudden dyspnea without hemoptysis. Option C has gradual onset. Option D does not cause hemoptysis.", "Pulmonary Embolism", "Clinical Presentation", ["respiratory", "PE", "DVT", "assessment"], "PE classic triad: sudden dyspnea, pleuritic chest pain, hemoptysis. Risk factors: Virchow's triad (stasis, endothelial injury, hypercoagulability). CT-PA is diagnostic gold standard."),

  q("Respiratory", 2, "A client with a laryngectomy requires suctioning. The nurse should:", ["Suction through the nose", "Suction through the stoma, which is now the client's only airway", "Suction through the mouth only", "Avoid suctioning as it is contraindicated"], 1, "After total laryngectomy, the client breathes exclusively through the stoma. There is no connection between the upper airway and the trachea. Nasal and oral suctioning will not reach the lower airway. The nurse must suction through the stoma using sterile technique. A humidifier is essential to prevent mucus crusting since air no longer passes through the nose for humidification.", "Laryngectomy", "Airway Management", ["respiratory", "laryngectomy", "suctioning", "airway"], "Total laryngectomy: stoma = only airway. No connection between nose/mouth and lungs. Cannot drown (no water entry to lungs via mouth). Humidify stoma air."),

  q("Respiratory", 3, "A nurse is caring for a client with a flail chest. Which finding is characteristic of this injury?", ["Paradoxical chest wall movement during respiration", "Symmetrical chest expansion", "Hyperresonance on percussion", "Tracheal deviation to the affected side"], 0, "Flail chest occurs when three or more adjacent ribs are fractured in two or more places, creating a free-floating segment. This segment moves paradoxically — inward during inspiration and outward during expiration — impairing ventilation and gas exchange. Treatment focuses on pain management, positive pressure ventilation if needed, and monitoring for pulmonary contusion. Option B is the opposite of what occurs. Option C suggests pneumothorax. Option D suggests tension pneumothorax.", "Chest Trauma", "Flail Chest", ["respiratory", "trauma", "chest-wall", "assessment"], "Flail chest: paradoxical movement. Treat pain aggressively (epidural analgesia is preferred). Watch for underlying pulmonary contusion, which is the main cause of hypoxemia."),

  q("Respiratory", 4, "A client in the ICU develops ventilator-associated pneumonia (VAP). Which nursing intervention is most effective for VAP prevention?", ["Administering prophylactic antibiotics to all ventilated patients", "Elevating the head of bed 30-45 degrees and performing oral care with chlorhexidine", "Using heated humidifiers instead of heat-moisture exchangers", "Changing the ventilator circuit every 24 hours"], 1, "Evidence-based VAP prevention bundle includes: HOB elevation 30-45 degrees, oral care with chlorhexidine every 2-4 hours, sedation vacations and daily spontaneous breathing trials, DVT prophylaxis, peptic ulcer prophylaxis, and maintaining ETT cuff pressure 20-30 cmH2O. Option A promotes antibiotic resistance. Option C is not part of the VAP bundle. Option D — routine circuit changes do not reduce VAP.", "Ventilator-Associated Pneumonia", "Prevention Bundle", ["respiratory", "VAP", "critical-care", "infection-prevention"], "VAP bundle: HOB 30-45°, oral care with chlorhexidine, daily sedation vacation, SBT, DVT and ulcer prophylaxis. Do NOT routinely change ventilator circuits."),

  q("Respiratory", 3, "A nurse is educating a client about the proper use of a metered-dose inhaler (MDI) with a spacer. Which instruction is correct?", ["Exhale fully, then inhale quickly and forcefully through the spacer", "Exhale fully, actuate the inhaler into the spacer, then inhale slowly and deeply for 3-5 seconds", "Hold breath for 2 seconds after inhalation", "Shake the spacer vigorously after each use"], 1, "Proper MDI-spacer technique: shake inhaler, exhale fully, place spacer mouthpiece in mouth, actuate the canister, then inhale slowly and deeply for 3-5 seconds. Hold breath for 10 seconds to allow medication deposition in the airways. Wait 1 minute between puffs. Option A (quick forceful inhalation) causes medication to deposit in the oropharynx instead of the lungs. Option C — hold breath for 10 seconds, not 2. Option D — shake the inhaler, not the spacer.", "Asthma", "Inhaler Technique", ["respiratory", "inhalers", "patient-education", "asthma"], "MDI technique: Shake, exhale, actuate into spacer, inhale SLOWLY 3-5 sec, hold breath 10 sec. Spacer increases lung deposition from 10% to 20%."),

  q("Respiratory", 3, "A client with obstructive sleep apnea (OSA) is prescribed CPAP therapy. The nurse should educate the client that untreated OSA increases the risk of:", ["Osteoporosis", "Hypertension, cardiac dysrhythmias, and stroke", "Hyperthyroidism", "Kidney stones"], 1, "Untreated OSA causes repeated episodes of hypoxemia and hypercapnia during sleep, leading to sympathetic activation and increased cardiovascular risk. Complications include systemic hypertension, pulmonary hypertension, cardiac dysrhythmias (especially atrial fibrillation), heart failure, stroke, and increased motor vehicle accidents due to daytime somnolence. Options A, C, and D are not directly associated with OSA.", "Sleep Apnea", "Complications", ["respiratory", "sleep-apnea", "CPAP", "cardiovascular-risk"], "Untreated OSA complications: HTN, AFib, heart failure, stroke, pulmonary HTN, daytime somnolence, MVA risk. CPAP is first-line treatment."),

  q("Respiratory", 2, "A nurse is preparing a client for a bronchoscopy. Which pre-procedure instruction is essential?", ["The client should eat a full meal 1 hour before the procedure", "The client must be NPO for at least 6-8 hours before the procedure", "The client should take all morning medications with a full glass of water", "No preparation is needed for this procedure"], 1, "Bronchoscopy requires NPO status for 6-8 hours to reduce aspiration risk, as the throat is anesthetized with a local anesthetic spray (lidocaine), which abolishes the gag reflex. Post-procedure, NPO is maintained until the gag reflex returns (typically 2 hours). Option A creates aspiration risk. Options C and D are incorrect preparation instructions.", "Bronchoscopy", "Pre-Procedure Care", ["respiratory", "bronchoscopy", "procedures", "pre-operative"], "Bronchoscopy: NPO 6-8 hours pre. Post-procedure: NPO until gag reflex returns (~2 hours). Monitor for laryngospasm, bronchospasm, and bleeding."),

  q("Respiratory", 3, "A nurse notes that a client's chest X-ray shows a completely white-out right hemithorax. Combined with tracheal deviation toward the affected side, this most likely represents:", ["Large pleural effusion", "Lung collapse (atelectasis) of the right lung", "Tension pneumothorax", "Right lower lobe pneumonia"], 1, "A white-out hemithorax with tracheal deviation TOWARD the affected side indicates volume loss — the lung has collapsed (atelectasis), and the mediastinal structures are pulled toward the side of collapse. In contrast, a white-out with tracheal deviation AWAY from the affected side indicates a massive pleural effusion (fluid pushing structures away). Option C (tension pneumothorax) shows hyperinflation, not white-out. Option D would not cause complete white-out.", "Atelectasis", "Chest X-ray Interpretation", ["respiratory", "CXR", "atelectasis", "assessment"], "CXR interpretation: Trachea shifts TOWARD = volume loss (atelectasis). Trachea shifts AWAY = space-occupying (effusion, tension pneumothorax)."),

  q("Respiratory", 4, "A nurse is caring for a client with cystic fibrosis who is receiving high-dose pancreatic enzyme replacement. The nurse should monitor for:", ["Hypoglycemia", "Fibrosing colonopathy from excessive enzyme doses", "Hyperkalemia", "Pulmonary fibrosis"], 1, "High-dose pancreatic enzyme replacement therapy (>6,000 lipase units/kg/meal) in cystic fibrosis patients is associated with fibrosing colonopathy — a stricturing condition of the colon. Enzyme doses should be titrated to the minimum effective dose. Signs include abdominal pain, bloody stools, and bowel obstruction. Options A, C, and D are not direct complications of enzyme replacement therapy.", "Cystic Fibrosis", "Pancreatic Enzyme Therapy", ["respiratory", "cystic-fibrosis", "pharmacology", "GI"], "CF enzyme replacement: take with every meal and snack. Do not exceed 6,000 lipase units/kg/meal to avoid fibrosing colonopathy. Assess stool frequency and character."),

  // ============================================================
  // MEDICAL-SURGICAL: GASTROINTESTINAL (40 questions)
  // ============================================================
  q("Gastrointestinal", 3, "A nurse is caring for a client with acute pancreatitis. Which laboratory finding is most specific for this diagnosis?", ["Elevated WBC count", "Elevated serum lipase", "Elevated ALT", "Elevated blood glucose"], 1, "Serum lipase is the most specific marker for acute pancreatitis (remains elevated for 7-14 days). Serum amylase is also elevated but is less specific as it rises in other conditions (parotitis, bowel obstruction). Option A (WBC) indicates inflammation but is non-specific. Option C (ALT) is more specific for liver disease. Option D (glucose) may be elevated but is non-specific.", "Pancreatitis", "Diagnostic Markers", ["GI", "pancreatitis", "lab-values", "diagnostics"], "Pancreatitis labs: Lipase is most specific (elevated 7-14 days). Amylase rises first but less specific. Ranson's criteria and APACHE II predict severity."),

  q("Gastrointestinal", 2, "A client with a peptic ulcer is prescribed omeprazole. The nurse should instruct the client to take this medication:", ["With meals for better absorption", "30-60 minutes before the first meal of the day on an empty stomach", "At bedtime only", "Only when experiencing symptoms"], 1, "Proton pump inhibitors (PPIs) like omeprazole are most effective when taken 30-60 minutes before the first meal. They inhibit the hydrogen-potassium ATPase pump in parietal cells, reducing acid secretion. Taking before a meal maximizes the number of active proton pumps available for inhibition. Options A, C, and D reduce effectiveness. Long-term PPI use is associated with C. difficile infection, osteoporosis, and hypomagnesemia.", "Peptic Ulcer Disease", "PPI Therapy", ["GI", "peptic-ulcer", "pharmacology", "patient-education"], "PPIs: take 30-60 min before first meal. Long-term risks: C. diff, osteoporosis, hypomagnesemia, B12 deficiency. Taper when discontinuing to prevent rebound acid."),

  q("Gastrointestinal", 3, "A nurse is assessing a client with cirrhosis who develops increasing abdominal girth, shifting dullness, and a fluid wave. These findings indicate:", ["Paralytic ileus", "Ascites", "Small bowel obstruction", "Peritonitis"], 1, "Increasing abdominal girth, shifting dullness on percussion, and a positive fluid wave test are classic findings of ascites — fluid accumulation in the peritoneal cavity. In cirrhosis, ascites results from portal hypertension, decreased albumin production, and sodium/water retention. Management includes sodium restriction, diuretics (spironolactone + furosemide), and paracentesis for large volumes. Option A causes absent bowel sounds and distension. Option C causes colicky pain. Option D causes rebound tenderness.", "Cirrhosis", "Ascites", ["GI", "cirrhosis", "ascites", "assessment"], "Ascites assessment: measure abdominal girth daily (same location, same time). Fluid wave = moderate-large ascites. Shifting dullness = >500 mL fluid. Paracentesis: max 5L per session."),

  q("Gastrointestinal", 4, "A client with ulcerative colitis is admitted with 15-20 bloody stools per day, temperature 39°C, and hemoglobin of 8.5 g/dL. The nurse recognizes this as:", ["Mild ulcerative colitis exacerbation", "Fulminant colitis requiring aggressive treatment and possible surgical consult", "Irritable bowel syndrome flare", "Normal disease course"], 1, "Fulminant colitis criteria include >10 bloody stools/day, temperature >38.5°C, tachycardia, hemoglobin <10 g/dL, and ESR >30. This is a medical emergency requiring IV corticosteroids, fluid resuscitation, correction of anemia, and close monitoring for toxic megacolon. Surgical consultation for colectomy should be obtained early. Option A underestimates severity. Option C does not cause bloody stools. Option D is incorrect.", "Inflammatory Bowel Disease", "Fulminant Colitis", ["GI", "ulcerative-colitis", "IBD", "emergency"], "Fulminant UC: >10 bloody stools/day + fever + tachycardia + anemia. Watch for toxic megacolon (colon >6cm on X-ray). Surgical backup essential."),

  q("Gastrointestinal", 2, "A client with hepatic encephalopathy is prescribed lactulose. The nurse should monitor for the desired effect of:", ["Decreased urinary output", "2-3 soft stools per day", "Increased serum ammonia levels", "Weight gain"], 1, "Lactulose is an osmotic laxative that draws ammonia into the colon for elimination. The goal is 2-3 soft stools per day to remove ammonia from the body. Too many stools cause dehydration and electrolyte imbalances. Too few stools allow ammonia to accumulate. Option A (decreased UO) suggests dehydration. Option C is the opposite of the desired effect. Option D is not a therapeutic goal.", "Hepatic Encephalopathy", "Lactulose Therapy", ["GI", "cirrhosis", "hepatic-encephalopathy", "pharmacology"], "Lactulose goal: 2-3 soft stools/day. Too many = dehydration/hypokalemia. Too few = ammonia accumulation. Also give rifaximin as adjunct therapy."),

  q("Gastrointestinal", 3, "A nurse is caring for a client post-liver biopsy. Which position should the client be placed in, and for how long?", ["Supine with legs elevated for 2 hours", "Right lateral position with a pillow or rolled towel under the puncture site for 2-4 hours", "Left lateral position for 1 hour", "Prone position for 6 hours"], 1, "After percutaneous liver biopsy, the client is positioned on the right side with a pillow/rolled towel under the costal margin to apply pressure to the puncture site and prevent hemorrhage. This position is maintained for 2-4 hours. The nurse should monitor vital signs every 15 minutes for the first hour, assess for hemorrhage (tachycardia, hypotension, right shoulder pain from diaphragmatic irritation), and pneumothorax.", "Liver Biopsy", "Post-Procedure Care", ["GI", "liver", "biopsy", "post-procedure"], "Post-liver biopsy: right side-lying 2-4 hrs. Right shoulder pain = diaphragmatic irritation from bile leak or hemorrhage. Monitor VS q15min x 1hr."),

  q("Gastrointestinal", 3, "A client with Crohn's disease is most likely to develop deficiency in which vitamin?", ["Vitamin C", "Vitamin B12", "Vitamin K", "Vitamin A"], 1, "Crohn's disease commonly affects the terminal ileum, which is the primary absorption site for vitamin B12 and bile salts. Chronic terminal ileal inflammation or surgical resection leads to B12 malabsorption, causing megaloblastic anemia and neurological complications. Option A is absorbed in the upper GI tract. Option C is absorbed with fat in the proximal intestine (though fat-soluble vitamin deficiencies can occur). Option D is also absorbed proximally.", "Inflammatory Bowel Disease", "Nutritional Deficiencies", ["GI", "crohns-disease", "IBD", "nutrition"], "Crohn's disease and B12: terminal ileum = B12 absorption site. Also malabsorbs bile salts leading to steatorrhea. May need B12 injections if ileum is resected."),

  q("Gastrointestinal", 2, "A client with a colostomy has watery output. The nurse identifies the colostomy is most likely located in the:", ["Sigmoid colon", "Descending colon", "Ascending colon", "Transverse colon"], 2, "Colostomy output consistency depends on location: ascending colon produces liquid/watery stool (minimal water absorption has occurred), transverse colon produces semi-formed stool, descending colon produces increasingly formed stool, and sigmoid colon produces formed stool similar to normal bowel movements. Option A and B would produce formed to semi-formed stool. Option D produces semi-formed stool.", "Colostomy", "Output Assessment", ["GI", "colostomy", "ostomy-care", "assessment"], "Colostomy output: ascending = liquid, transverse = semi-formed, descending = semi-formed to formed, sigmoid = formed. Ileostomy is always liquid with high enzyme content."),

  q("Gastrointestinal", 3, "A nurse is caring for a client admitted with an upper GI bleed. The client vomits bright red blood. The nurse should:", ["Place the client NPO, start two large-bore IVs, and prepare for possible endoscopy", "Administer an antiemetic and continue oral intake", "Encourage the client to drink cold water", "Position the client supine and elevate the legs"], 0, "Active hematemesis (bright red blood vomiting) indicates acute upper GI bleeding requiring: NPO status, two large-bore IV catheters (16-18 gauge) for fluid resuscitation and blood products, type and crossmatch, CBC, coagulation studies, and preparation for emergent endoscopy. The client should be positioned with the head elevated or on the side to prevent aspiration. Option B delays critical treatment. Option C is contraindicated. Option D risks aspiration.", "Upper GI Bleeding", "Emergency Management", ["GI", "GI-bleeding", "emergency", "hematemesis"], "Upper GI bleed: 2 large-bore IVs, type and crossmatch, CBC, NPO, PPI infusion, emergent EGD. Assess for hemodynamic instability: tachycardia, hypotension, altered mental status."),

  q("Gastrointestinal", 3, "A nurse is teaching a client with gastroesophageal reflux disease (GERD) about lifestyle modifications. Which instruction should be included?", ["Lie down immediately after meals to aid digestion", "Elevate the head of bed 6-8 inches and avoid eating 2-3 hours before bedtime", "Increase intake of chocolate, coffee, and mint", "Wear tight-fitting clothing to support the abdomen"], 1, "GERD lifestyle modifications: HOB elevation 6-8 inches (not just extra pillows), avoid eating 2-3 hours before bed, small frequent meals, avoid trigger foods (caffeine, chocolate, mint, alcohol, acidic/spicy foods, fatty foods), weight loss if overweight, and avoid tight clothing. Option A worsens reflux. Option C includes trigger foods. Option D increases intra-abdominal pressure.", "GERD", "Lifestyle Modifications", ["GI", "GERD", "patient-education", "nutrition"], "GERD triggers: Chocolate, Alcohol, Mint, Peppermint, Spicy, Acidic, Fatty foods, Caffeine. Elevate HOB with blocks (not just pillows — that flexes the abdomen)."),

  q("Gastrointestinal", 4, "A client with a bowel obstruction has a nasogastric tube to low intermittent suction. The nurse notes the drainage is green-brown with a fecal odor. This suggests:", ["Gastric ulcer bleeding", "A distal small bowel or large bowel obstruction", "Normal NG drainage", "Esophageal varices"], 1, "Green-brown, feculent (fecal-smelling) NG drainage indicates the obstruction is located distally in the small bowel or in the large bowel, allowing intestinal contents and bacteria to back up. This finding suggests a more serious obstruction and possible need for surgical intervention. Option A would produce coffee-ground or bloody drainage. Option C is incorrect — normal NG drainage is green/yellow. Option D would produce frank blood.", "Bowel Obstruction", "Assessment Findings", ["GI", "bowel-obstruction", "NG-tube", "assessment"], "NG drainage colors: Green = bile (normal). Coffee-ground = old blood. Bright red = active bleeding. Feculent = distal obstruction. Always document color, amount, and consistency."),

  q("Gastrointestinal", 3, "A nurse is caring for a client who underwent a Whipple procedure (pancreaticoduodenectomy). Postoperative priorities include monitoring for:", ["Hyperglycemia only", "Hemorrhage, anastomotic leak, and pancreatic fistula", "Constipation", "Urinary retention"], 1, "The Whipple procedure removes the head of the pancreas, duodenum, gallbladder, and part of the common bile duct. Major postoperative complications include hemorrhage, anastomotic leak, pancreatic fistula (elevated drain amylase), delayed gastric emptying, and endocrine/exocrine pancreatic insufficiency. Close monitoring of drain output, blood glucose, and nutritional status is essential. Options A, C, and D are incomplete or incorrect priorities.", "Pancreatic Surgery", "Post-Whipple Care", ["GI", "pancreatic-surgery", "post-operative", "complications"], "Post-Whipple: monitor JP drain amylase (elevated = fistula). Watch for DGE (delayed gastric emptying). Long-term: pancreatic enzyme replacement and possible insulin."),

  q("Gastrointestinal", 2, "A client with cholecystitis asks about dietary modifications after cholecystectomy. The nurse should teach:", ["A strict fat-free diet is permanent", "Gradually reintroduce fats; most clients can resume a regular diet within 4-6 weeks", "High-fat meals are encouraged immediately", "There are no dietary changes needed"], 1, "After cholecystectomy, bile flows continuously into the duodenum instead of being stored and concentrated. Most clients can gradually resume a normal diet within 4-6 weeks. Initially, a low-fat diet may reduce diarrhea and GI discomfort. Some clients experience postcholecystectomy syndrome with diarrhea and bloating. Option A is unnecessarily restrictive. Option C may cause GI distress. Option D ignores the need for gradual dietary progression.", "Cholecystectomy", "Post-Surgical Diet", ["GI", "cholecystectomy", "nutrition", "patient-education"], "Post-cholecystectomy: Low-fat diet initially, then gradually increase. 10-20% of patients develop postcholecystectomy diarrhea from constant bile flow into duodenum."),

  q("Gastrointestinal", 3, "A nurse is assessing a client with suspected appendicitis. Which assessment finding is most characteristic?", ["Left lower quadrant pain", "Rebound tenderness at McBurney's point with positive Rovsing sign", "Epigastric pain radiating to the back", "Diffuse abdominal pain without localization"], 1, "McBurney's point is located one-third of the distance from the anterior superior iliac spine to the umbilicus in the right lower quadrant. Rebound tenderness at this point is highly suggestive of appendicitis. Rovsing sign (pain in the RLQ when palpating the LLQ) confirms peritoneal irritation. Option A (LLQ pain) suggests diverticulitis. Option C suggests pancreatitis. Option D is non-specific.", "Appendicitis", "Clinical Assessment", ["GI", "appendicitis", "assessment", "emergency"], "Appendicitis signs: McBurney's point tenderness, Rovsing sign (RLQ pain with LLQ palpation), psoas sign, obturator sign. NPO — no laxatives, enemas, or heat application."),

  q("Gastrointestinal", 3, "A client with hepatitis C is being evaluated for antiviral therapy. The nurse should explain that current treatment involves:", ["Interferon injections for 48 weeks", "Direct-acting antivirals (DAAs) taken orally for 8-12 weeks with cure rates above 95%", "Lifelong suppressive therapy similar to HIV", "No effective treatment exists"], 1, "Direct-acting antivirals (DAAs) such as sofosbuvir/velpatasvir or glecaprevir/pibrentasvir have revolutionized hepatitis C treatment with cure rates >95% and treatment durations of 8-12 weeks. The old interferon-based regimens had lower cure rates and significant side effects. Option A is outdated treatment. Option C is incorrect — HCV can be cured. Option D is factually wrong.", "Hepatitis C", "Antiviral Treatment", ["GI", "hepatitis-C", "pharmacology", "infectious-disease"], "Hepatitis C is CURABLE with DAAs (>95% SVR). Treatment: 8-12 weeks oral therapy. Screen all adults born 1945-1965 (baby boomers) and all pregnant women."),

  q("Gastrointestinal", 2, "A nurse is providing dietary education to a client with diverticulosis. The nurse should recommend:", ["A low-fiber, low-residue diet", "A high-fiber diet with adequate fluid intake to prevent diverticulitis", "Avoidance of all fruits and vegetables", "A clear liquid diet indefinitely"], 1, "Diverticulosis (asymptomatic pouches) is managed with a high-fiber diet (25-35 g/day) and adequate hydration to increase stool bulk, reduce colonic pressure, and prevent diverticulitis (infection/inflammation of diverticula). Note: during acute diverticulitis, the client is NPO or on clear liquids until inflammation resolves. Option A is for acute diverticulitis. Option C eliminates fiber sources. Option D is overly restrictive for diverticulosis.", "Diverticular Disease", "Dietary Management", ["GI", "diverticular-disease", "nutrition", "patient-education"], "Diverticulosis = high-fiber diet. Diverticulitis = NPO then low-residue. The old advice to avoid nuts and seeds has been DEBUNKED by research."),

  // ============================================================
  // MEDICAL-SURGICAL: RENAL (40 questions)
  // ============================================================
  q("Renal/Urinary", 3, "A client with chronic kidney disease stage 3 has a phosphorus level of 6.2 mg/dL. The nurse anticipates which medication will be prescribed?", ["Calcium acetate (PhosLo) taken with meals", "Potassium chloride supplement", "Sodium bicarbonate IV push", "Vitamin D supplement alone"], 0, "Elevated phosphorus in CKD is managed with phosphate binders such as calcium acetate (PhosLo) or sevelamer (Renagel). These medications must be taken WITH meals to bind dietary phosphorus in the gut and prevent absorption. Uncontrolled hyperphosphatemia leads to renal osteodystrophy and vascular calcification. Option B would worsen hyperkalemia common in CKD. Option C does not address phosphorus. Option D alone does not lower phosphorus.", "Chronic Kidney Disease", "Phosphorus Management", ["renal", "CKD", "phosphorus", "pharmacology"], "Phosphate binders: MUST take with meals (bind phosphorus in food). Calcium-based binders may cause hypercalcemia. Sevelamer is calcium-free alternative."),

  q("Renal/Urinary", 2, "A nurse is teaching a client scheduled for hemodialysis about the arteriovenous fistula in the left arm. Which instruction is correct?", ["Blood pressure measurements may be taken on the left arm between treatments", "Avoid blood pressure measurements, venipuncture, and restrictive clothing on the fistula arm", "The fistula can be used immediately after creation", "Sleep on the left arm to apply pressure to the fistula"], 1, "AV fistula protection measures: no BP measurements, no venipuncture, no IV insertion, no restrictive clothing or jewelry on the fistula arm. Check for thrill (palpable buzzing/vibration) and bruit (audible whooshing with stethoscope) regularly. The fistula requires 6-8 weeks to mature before use. Option A risks damage to the fistula. Option C — fistulas need 6-8 weeks to mature. Option D can occlude blood flow.", "Hemodialysis", "AV Fistula Care", ["renal", "hemodialysis", "vascular-access", "patient-education"], "AV fistula: matures in 6-8 weeks. Check thrill and bruit daily. No BP, venipuncture, or constrictive items on fistula arm. Elevate post-dialysis if bleeding occurs."),

  q("Renal/Urinary", 3, "A client receiving peritoneal dialysis develops cloudy dialysate effluent with abdominal pain and fever. The nurse suspects:", ["Normal peritoneal dialysis finding", "Peritonitis requiring immediate culture and antibiotic therapy", "Insufficient dwell time", "Fluid overload"], 1, "Cloudy peritoneal dialysate with abdominal pain and fever is the hallmark of peritonitis — the most common complication of peritoneal dialysis. The nurse should obtain a sample for culture and cell count, initiate intraperitoneal antibiotics as prescribed, and assess vital signs. Staphylococcus aureus and Staphylococcus epidermidis are the most common causative organisms. Option A is incorrect. Options C and D do not cause cloudy effluent.", "Peritoneal Dialysis", "Peritonitis", ["renal", "peritoneal-dialysis", "infection", "complications"], "PD peritonitis: cloudy effluent + abdominal pain + fever. Culture effluent, give intraperitoneal antibiotics. Prevent with strict aseptic technique during exchanges."),

  q("Renal/Urinary", 4, "A nurse is caring for a client with acute kidney injury who is oliguric with a serum potassium of 6.5 mEq/L. The ECG shows peaked T-waves. The priority intervention is:", ["Oral kayexalate", "IV calcium gluconate to stabilize the cardiac membrane", "Hemodialysis", "Dietary potassium restriction"], 1, "With hyperkalemia and ECG changes (peaked T-waves), cardiac membrane stabilization with IV calcium gluconate is the immediate priority to prevent fatal dysrhythmias. Calcium gluconate does NOT lower potassium but protects the heart while other measures take effect (insulin + glucose, sodium bicarbonate, albuterol nebulizer, kayexalate, or emergent dialysis). Option A is too slow for this emergency. Option C is definitive but takes time to set up. Option D is a long-term measure.", "Acute Kidney Injury", "Hyperkalemia Management", ["renal", "AKI", "hyperkalemia", "emergency"], "Hyperkalemia with ECG changes: 1st = IV calcium gluconate (cardioprotection). Then insulin+glucose (shifts K+ intracellularly). Then eliminate K+ (kayexalate, dialysis)."),

  q("Renal/Urinary", 2, "A nurse is assessing a client's urine output after renal transplant surgery. Which finding requires immediate reporting?", ["Urine output of 100 mL/hour in the first 24 hours", "Urine output of less than 30 mL/hour", "Clear, pale yellow urine", "Mild hematuria in the first 24 hours"], 1, "Adequate urine output (>30 mL/hour) in the immediate post-transplant period indicates functioning graft. Oliguria (<30 mL/hour) may indicate acute rejection, renal artery thrombosis, ureteral obstruction, or ATN and requires immediate evaluation. Option A is expected/desired. Option C is normal. Option D is common immediately post-surgery.", "Renal Transplant", "Post-Operative Monitoring", ["renal", "transplant", "urine-output", "post-operative"], "Post-renal transplant: monitor UO hourly (expect brisk diuresis). Oliguria = potential rejection or vascular complication. Signs of rejection: fever, graft tenderness, decreased UO, elevated creatinine."),

  q("Renal/Urinary", 3, "A client with nephrotic syndrome has massive proteinuria, hypoalbuminemia, and generalized edema. The nurse should anticipate which dietary modification?", ["High-sodium, low-protein diet", "Moderate protein intake with sodium restriction", "Unrestricted sodium and protein", "Strict protein restriction"], 1, "Nephrotic syndrome management includes moderate protein intake (0.8-1.0 g/kg/day — enough to replace urinary losses without overloading damaged kidneys), sodium restriction (<2 g/day) to reduce edema, and diuretic therapy. Excessive protein intake can worsen proteinuria and accelerate kidney damage. Option A worsens edema. Option C is uncontrolled. Option D leads to malnutrition.", "Nephrotic Syndrome", "Dietary Management", ["renal", "nephrotic-syndrome", "nutrition", "edema"], "Nephrotic syndrome: massive proteinuria (>3.5g/day), hypoalbuminemia, edema, hyperlipidemia. Diet: moderate protein, low sodium. Monitor for DVT (loss of antithrombin III in urine)."),

  q("Renal/Urinary", 3, "A nurse is caring for a client with renal calculi. The client reports severe flank pain radiating to the groin with nausea and vomiting. The nurse should:", ["Encourage bedrest and restrict fluids", "Administer prescribed analgesics and strain all urine", "Apply ice to the flank area", "Prepare the client for immediate surgery"], 1, "Renal colic is one of the most painful conditions. Priority is pain management with NSAIDs (ketorolac) or opioids. All urine must be strained to capture the stone for analysis (composition determines prevention strategy). Increase fluid intake to >2,500 mL/day to facilitate stone passage. Most stones <5mm pass spontaneously. Option A (fluid restriction) is contraindicated. Option C is not standard treatment. Option D is not always necessary.", "Renal Calculi", "Acute Management", ["renal", "kidney-stones", "pain-management", "assessment"], "Renal calculi: strain ALL urine. Increase fluids >2.5L/day. Stones <5mm usually pass spontaneously. Stone types: calcium oxalate (most common), uric acid, struvite, cystine."),

  q("Renal/Urinary", 3, "A nurse is monitoring a client on continuous bladder irrigation (CBI) after transurethral resection of the prostate (TURP). Which finding indicates a complication?", ["Light pink irrigation output", "Dark red output with clots that does not clear with increased irrigation rate", "Mild bladder spasms", "Slight urethral discomfort"], 1, "Post-TURP CBI should produce light pink to clear output. Dark red output with persistent clots despite increased irrigation rate suggests hemorrhage or clot retention requiring intervention. The nurse should increase the irrigation rate, notify the provider, and assess vital signs. Option A is expected/normal. Option C is common and treated with antispasmodics. Option D is expected.", "BPH/TURP", "Post-Operative Complications", ["renal", "TURP", "CBI", "post-operative"], "Post-TURP: CBI should run fast enough to keep output light pink. Bright red = arterial bleeding (surgical). Dark red with clots = venous (increase irrigation). Watch for TURP syndrome (hyponatremia from irrigant absorption)."),

  q("Renal/Urinary", 2, "A client with a urinary tract infection asks why the nurse is recommending increased fluid intake. The nurse's best response is:", ["Fluids dilute the bacteria but do not help eliminate them", "Increased fluids flush bacteria from the urinary tract and dilute urine to reduce irritation", "Fluids replace antibiotics in treating UTIs", "Only cranberry juice is effective for UTI treatment"], 1, "Increased fluid intake (2-3 L/day) helps flush bacteria from the urinary tract, dilutes urine concentration (reducing mucosal irritation), and promotes frequent voiding, which prevents bacterial stasis. This is adjunctive therapy alongside antibiotics. Option A is partially correct but incomplete. Option C is incorrect — antibiotics are essential. Option D — cranberry may help prevent UTIs but does not treat them.", "Urinary Tract Infection", "Fluid Management", ["renal", "UTI", "patient-education", "hydration"], "UTI prevention: adequate fluids (2-3L/day), void frequently, wipe front to back, avoid irritants (caffeine, alcohol). Cranberry may prevent adhesion of E. coli to bladder wall."),

  q("Renal/Urinary", 4, "A nurse is caring for a client with rhabdomyolysis. Which renal complication should the nurse monitor for?", ["Renal calculi", "Acute kidney injury from myoglobin-induced tubular obstruction", "Nephrotic syndrome", "Polycystic kidney disease"], 1, "Rhabdomyolysis releases large amounts of myoglobin from damaged skeletal muscle. Myoglobin is nephrotoxic — it precipitates in renal tubules, causing obstruction and acute tubular necrosis. Aggressive IV fluid resuscitation (200-300 mL/hour initially) is essential to maintain renal perfusion and flush myoglobin. Monitor CK levels (>5,000 U/L indicates significant rhabdomyolysis), urine output, and renal function. Option A is not a direct complication. Options C and D are unrelated.", "Rhabdomyolysis", "Renal Complications", ["renal", "rhabdomyolysis", "AKI", "critical-care"], "Rhabdomyolysis: dark brown urine (tea/cola colored), elevated CK (>5x normal), hyperkalemia. Treatment: aggressive IV NS (200-300 mL/hr), target UO >200 mL/hr. Avoid lactated Ringer's (contains potassium)."),

  q("Renal/Urinary", 3, "A client on hemodialysis develops hypotension, nausea, and muscle cramps during the session. The nurse should:", ["Continue dialysis at the current rate", "Stop ultrafiltration, place the client in Trendelenburg, and administer a normal saline bolus", "Increase the blood flow rate", "Administer a dose of antihypertensive medication"], 1, "Intradialytic hypotension is the most common complication of hemodialysis, caused by rapid fluid removal. Management: stop ultrafiltration, lower the client's legs (Trendelenburg if tolerated), administer 100-200 mL NS bolus, and reassess. Option A worsens the problem. Option C increases hemodynamic stress. Option D would further lower blood pressure.", "Hemodialysis", "Intradialytic Complications", ["renal", "hemodialysis", "hypotension", "complications"], "Intradialytic hypotension: stop UF, Trendelenburg, NS bolus 100-200 mL. Prevention: accurate dry weight assessment, sodium modeling, cool dialysate temperature."),

  q("Renal/Urinary", 3, "A nurse is assessing a client with glomerulonephritis. Which urine finding is characteristic?", ["Clear, pale yellow urine with no protein", "Smoky, brown-colored urine with proteinuria and RBC casts", "Bright red hematuria with clots", "Crystal-clear urine with glucose"], 1, "Glomerulonephritis produces smoky or cola-colored urine due to hematuria. Urinalysis shows proteinuria, RBC casts (pathognomonic for glomerulonephritis), and dysmorphic RBCs. Additional findings include edema, hypertension, and decreased GFR. Option A is normal urine. Option C suggests lower urinary tract bleeding. Option D suggests diabetes mellitus.", "Glomerulonephritis", "Urinalysis Findings", ["renal", "glomerulonephritis", "urinalysis", "assessment"], "Glomerulonephritis: smoky/cola-colored urine, RBC casts (pathognomonic), proteinuria, edema, HTN. Often follows streptococcal pharyngitis (post-streptococcal GN) by 1-2 weeks."),

  // ============================================================
  // MEDICAL-SURGICAL: NEUROLOGICAL (40 questions)
  // ============================================================
  q("Neurological", 3, "A nurse is caring for a client with increased intracranial pressure (ICP). The client's ICP monitoring shows a reading of 22 mmHg. Which nursing intervention should be performed first?", ["Lower the head of bed to flat", "Elevate the head of bed 30 degrees and maintain the head in a neutral midline position", "Administer aspirin for headache", "Encourage coughing and deep breathing exercises"], 1, "Normal ICP is 0-15 mmHg. An ICP of 22 mmHg is elevated. HOB elevation at 30 degrees promotes venous drainage from the brain. Maintaining neutral head alignment prevents compression of the jugular veins, which would impede venous return and worsen ICP. Option A would increase ICP. Option C — aspirin can increase bleeding risk. Option D — coughing increases ICP.", "Increased ICP", "Nursing Interventions", ["neuro", "ICP", "positioning", "critical-care"], "ICP management: HOB 30°, neutral head alignment, avoid hip flexion, avoid Valsalva, hyperventilation PRN (target PaCO2 35-38), mannitol or hypertonic saline for acute elevation."),

  q("Neurological", 2, "A client is brought to the ED after a generalized tonic-clonic seizure. During the seizure, the nurse's priority action is to:", ["Insert a padded tongue blade into the client's mouth", "Protect the client from injury by clearing the area and placing padding under the head", "Restrain the client to prevent movement", "Administer oral phenytoin immediately"], 1, "During a seizure, the priority is patient safety: clear the area of hard objects, place padding under the head, position on the side if possible, and time the seizure. NEVER insert anything into the mouth (risk of broken teeth, aspiration, jaw fracture). Do NOT restrain the client. Administer IV benzodiazepines (lorazepam, diazepam) for seizures lasting >5 minutes (status epilepticus). Option A is contraindicated. Option C can cause injury. Option D — oral meds cannot be given during a seizure.", "Seizure Disorders", "Seizure Management", ["neuro", "seizures", "safety", "emergency"], "Seizure safety: protect from injury, time the seizure, position on side, NOTHING in the mouth. Status epilepticus = seizure >5 min or repeated seizures without recovery. Give IV lorazepam."),

  q("Neurological", 4, "A client with a subarachnoid hemorrhage develops sudden severe headache, nuchal rigidity, and photophobia. The nurse recognizes that the most serious complication to monitor for in the first 72 hours is:", ["Deep vein thrombosis", "Cerebral vasospasm", "Urinary tract infection", "Skin breakdown"], 1, "Cerebral vasospasm is the most dangerous complication following subarachnoid hemorrhage (SAH), typically occurring between days 4-14 (peak at day 7-10). It causes delayed cerebral ischemia and can lead to stroke. Prevention and treatment include nimodipine (calcium channel blocker), induced hypertension, and maintenance of euvolemia. Option A is important but not the most serious. Options C and D are not the priority concerns in SAH.", "Subarachnoid Hemorrhage", "Vasospasm", ["neuro", "SAH", "vasospasm", "critical-care"], "SAH vasospasm: peaks days 7-10. Nimodipine is standard prophylaxis (reduces poor outcomes, not vasospasm itself). Triple-H therapy: Hypertension, Hypervolemia, Hemodilution (older approach)."),

  q("Neurological", 3, "A nurse is performing a neurological assessment on a client using the Glasgow Coma Scale (GCS). The client opens eyes to pain, makes incomprehensible sounds, and withdraws from pain. The GCS score is:", ["6", "7", "8", "9"], 2, "GCS scoring: Eye opening to pain = 2, Verbal response (incomprehensible sounds) = 2, Motor response (withdrawal from pain) = 4. Total = 2 + 2 + 4 = 8. A GCS of 8 or less indicates severe brain injury and the need for airway protection (intubation). Option A is too low. Options B and D are incorrect calculations.", "Neurological Assessment", "Glasgow Coma Scale", ["neuro", "GCS", "assessment", "trauma"], "GCS: Eye (1-4) + Verbal (1-5) + Motor (1-6) = 3-15. GCS ≤ 8 = severe brain injury, intubate to protect airway. Document each component separately for trending."),

  q("Neurological", 3, "A client with Parkinson's disease is prescribed carbidopa-levodopa. The nurse should teach the client to avoid taking this medication with:", ["Orange juice", "High-protein meals that may reduce medication effectiveness", "Whole grain bread", "Vegetables"], 1, "Levodopa competes with dietary amino acids for absorption in the small intestine and transport across the blood-brain barrier. High-protein meals can significantly reduce levodopa's effectiveness. Clients should distribute protein intake evenly throughout the day or take medication 30-60 minutes before meals. Option A does not interfere. Options C and D have minimal impact compared to high-protein foods.", "Parkinson's Disease", "Medication Management", ["neuro", "parkinsons", "pharmacology", "patient-education"], "Levodopa + protein interaction: amino acids compete for absorption and BBB transport. Take 30-60 min before meals. Avoid high-protein meals close to dosing. Never abruptly discontinue."),

  q("Neurological", 3, "A nurse is caring for a client post-craniotomy. Which finding should be immediately reported to the surgeon?", ["Mild headache controlled with prescribed analgesics", "Clear fluid drainage from the nose with a positive halo sign", "Slightly elevated temperature of 37.5°C on postoperative day 1", "Mild periorbital edema"], 1, "Clear fluid drainage from the nose (rhinorrhea) with a positive halo sign (clear ring surrounding blood-tinged drainage on linen) indicates CSF leak. CSF leaks increase the risk of meningitis and require immediate intervention. The nurse should avoid nasal suctioning, keep the HOB elevated, and notify the surgeon. Options A, C, and D are common and expected post-craniotomy findings.", "Post-Craniotomy", "CSF Leak", ["neuro", "craniotomy", "CSF-leak", "post-operative"], "CSF leak signs: clear rhinorrhea or otorrhea, halo sign, positive glucose test on drainage. Do NOT pack the nose, suction, or have patient blow nose. HOB elevated."),

  q("Neurological", 2, "A nurse is assessing a client for signs of meningeal irritation. A positive Brudzinski sign is when:", ["Extension of the knee causes pain in the hamstring", "Flexion of the neck causes involuntary flexion of the hips and knees", "Dorsiflexion of the foot causes calf pain", "Percussion of the patellar tendon causes exaggerated reflex"], 1, "Brudzinski sign: passive flexion of the neck causes involuntary flexion of the hips and knees due to meningeal irritation. This is a classic sign of meningitis. Option A describes Kernig sign. Option C describes Homans sign (DVT, though this is no longer recommended). Option D describes hyperreflexia.", "Meningitis", "Assessment Signs", ["neuro", "meningitis", "assessment", "meningeal-signs"], "Meningeal signs: Brudzinski = neck flexion causes hip/knee flexion. Kernig = resistance to knee extension with hip flexed. Nuchal rigidity = neck stiffness. Photophobia is also common."),

  q("Neurological", 3, "A client with myasthenia gravis is experiencing a myasthenic crisis. The nurse should prepare for:", ["Administration of atropine", "IV edrophonium (Tensilon) test to differentiate from cholinergic crisis, and possible intubation", "Immediate discontinuation of all medications", "Application of a cooling blanket"], 1, "Myasthenic crisis is caused by insufficient anticholinesterase medication, leading to severe weakness and potential respiratory failure. The Tensilon test can differentiate: if symptoms improve with Tensilon, it is myasthenic crisis (need more medication); if symptoms worsen, it is cholinergic crisis (too much medication). Intubation may be necessary for respiratory failure. Option A is for cholinergic crisis. Option C could worsen symptoms. Option D is not indicated.", "Myasthenia Gravis", "Crisis Management", ["neuro", "myasthenia-gravis", "crisis", "emergency"], "Myasthenic crisis: weakness worsens (need MORE medication). Cholinergic crisis: SLUDGE symptoms (too MUCH medication). Tensilon test differentiates. Both can cause respiratory failure."),

  q("Neurological", 4, "A nurse is caring for a client with acute ischemic stroke. The tPA administration window is:", ["Within 12 hours of symptom onset", "Within 3-4.5 hours of symptom onset depending on inclusion criteria", "Within 24 hours of symptom onset", "Only when the client arrives at the hospital"], 1, "IV tPA (alteplase) for acute ischemic stroke must be administered within 3 hours of symptom onset (extended to 4.5 hours in select patients meeting additional criteria). Door-to-needle time goal is 60 minutes. Exclusions include hemorrhagic stroke, recent surgery, bleeding disorders, and uncontrolled hypertension. Option A is too long. Option C is for thrombectomy (up to 24 hours in select cases). Option D is vague.", "Stroke", "Thrombolytic Therapy", ["neuro", "stroke", "tPA", "time-sensitive"], "Stroke tPA window: 3 hrs (up to 4.5 hrs with additional criteria). Door-to-needle < 60 min. Thrombectomy for large vessel occlusion up to 24 hrs. Time is brain."),

  q("Neurological", 3, "A client with a spinal cord injury at C4 is at highest risk for:", ["Urinary retention only", "Respiratory failure requiring mechanical ventilation", "Lower extremity deep vein thrombosis only", "Autonomic dysreflexia only"], 1, "The diaphragm is innervated by the phrenic nerve (C3-C5). A C4 spinal cord injury can compromise diaphragmatic function, leading to respiratory failure requiring mechanical ventilation. Higher cervical injuries (C1-C3) result in complete ventilator dependence. While all options listed are concerns in SCI, respiratory failure is the most immediately life-threatening and takes priority. Options A, C, and D are also concerns but not the highest risk at C4.", "Spinal Cord Injury", "Respiratory Complications", ["neuro", "spinal-cord-injury", "respiratory", "critical-care"], "SCI respiratory risk: C3-C5 = phrenic nerve (diaphragm). C4 injury = impaired diaphragm function. Above C3 = ventilator dependent. Monitor FVC, NIF, and oxygen saturation closely."),

  q("Neurological", 2, "A nurse is caring for a client with a lumbar puncture scheduled. Which position should the client assume during the procedure?", ["Supine with legs extended", "Lateral recumbent with knees drawn up to the chest and chin tucked", "Prone with a pillow under the abdomen", "Sitting upright in a chair"], 1, "The lateral recumbent (fetal) position with knees drawn to chest and chin tucked opens the intervertebral spaces, allowing easier needle insertion into the subarachnoid space. An alternative is sitting on the edge of the bed leaning forward. Post-LP: the client should lie flat for several hours to prevent post-LP headache (caused by CSF leak). Option A does not open the spaces. Options C and D are not standard positions.", "Lumbar Puncture", "Positioning", ["neuro", "lumbar-puncture", "procedures", "positioning"], "LP position: lateral fetal or sitting forward. Post-LP: lie flat 4-8 hours, increase fluids, caffeine for headache. Complications: headache (most common), infection, herniation (rare)."),

  q("Neurological", 3, "A client with autonomic dysreflexia develops a pounding headache, blood pressure of 210/120 mmHg, and bradycardia. The nurse's first action is:", ["Administer IV labetalol", "Sit the client up immediately and check for the triggering stimulus", "Place the client in Trendelenburg position", "Administer IV atropine for the bradycardia"], 1, "Autonomic dysreflexia is a medical emergency in clients with SCI at T6 or above. The immediate priority is sitting the client upright (to lower BP by orthostatic mechanism) and identifying/removing the noxious stimulus. The most common trigger is bladder distension (check for kinked catheter, full drainage bag) followed by bowel distension. If BP remains elevated after removing the stimulus, antihypertensive medications are administered. Option A is appropriate only after positioning and stimulus removal. Option C would worsen hypertension. Option D is not indicated.", "Autonomic Dysreflexia", "Emergency Management", ["neuro", "autonomic-dysreflexia", "SCI", "emergency"], "Autonomic dysreflexia: sit up first, then find the trigger. #1 cause = bladder distension (check catheter). #2 = bowel impaction. Untreated can cause stroke, seizures, death."),

  q("Neurological", 3, "A nurse is assessing a client with multiple sclerosis. Which finding is characteristic of this disease?", ["Continuous progressive muscle weakness without remission", "Relapsing-remitting episodes of neurological dysfunction affecting different areas", "Resting tremor and shuffling gait", "Sudden onset of unilateral facial paralysis"], 1, "Multiple sclerosis is characterized by demyelination of the CNS with relapsing-remitting episodes affecting different neurological areas at different times (dissemination in space and time). Symptoms include optic neuritis, sensory changes, spasticity, fatigue, and bladder dysfunction. Option A describes ALS or myasthenia gravis. Option C describes Parkinson's disease. Option D describes Bell's palsy.", "Multiple Sclerosis", "Clinical Presentation", ["neuro", "multiple-sclerosis", "assessment", "autoimmune"], "MS hallmark: dissemination in space and time. Most common type: relapsing-remitting (85%). Charcot's triad: intention tremor, scanning speech, nystagmus. Uhthoff phenomenon: symptoms worsen with heat."),

  // ============================================================
  // MEDICAL-SURGICAL: ENDOCRINE (35 questions)
  // ============================================================
  q("Endocrine", 3, "A client with diabetic ketoacidosis (DKA) has a blood glucose of 450 mg/dL, pH 7.18, and serum potassium of 5.8 mEq/L. The nurse understands that the elevated potassium is caused by:", ["Renal failure", "Excessive potassium intake", "Acidosis causing potassium to shift out of cells, despite total body potassium depletion", "Hyperaldosteronism"], 2, "In DKA, metabolic acidosis causes hydrogen ions to move intracellularly in exchange for potassium ions moving extracellularly (transcellular shift). This creates a falsely elevated serum potassium despite total body potassium depletion. As insulin is administered and acidosis corrects, potassium rapidly shifts back into cells, potentially causing dangerous hypokalemia. Potassium replacement is essential before or with insulin therapy. Options A, B, and D are not the mechanism in DKA.", "Diabetic Ketoacidosis", "Electrolyte Shifts", ["endocrine", "DKA", "potassium", "acid-base"], "DKA potassium paradox: serum K+ may be HIGH but total body K+ is LOW. As insulin corrects acidosis, K+ drops rapidly. Replace K+ when level < 5.3 and UO adequate. Hold insulin if K+ < 3.3."),

  q("Endocrine", 2, "A nurse is teaching a client with type 2 diabetes about foot care. Which instruction is most important?", ["Soak feet in hot water daily to promote circulation", "Inspect feet daily for cuts, blisters, and skin changes", "Walk barefoot at home to toughen the feet", "Cut toenails in a rounded shape"], 1, "Daily foot inspection is critical because diabetic neuropathy reduces sensation, making clients unable to feel injuries. Small cuts, blisters, or pressure areas can progress to serious infections and ulcers. Option A — hot water can cause burns (neuropathy prevents feeling temperature). Option C — going barefoot increases injury risk. Option D — cut toenails straight across to prevent ingrown nails.", "Diabetes Management", "Foot Care", ["endocrine", "diabetes", "foot-care", "patient-education"], "Diabetic foot care: inspect daily, wash with warm (not hot) water, dry thoroughly between toes, moisturize but not between toes, wear shoes always, cut nails straight across, see podiatrist regularly."),

  q("Endocrine", 4, "A client with Addison's disease is admitted with an addisonian crisis. The nurse should anticipate administering:", ["IV insulin", "IV hydrocortisone and IV normal saline", "Oral prednisone taper", "IV potassium chloride"], 1, "Addisonian crisis (acute adrenal insufficiency) is a life-threatening emergency characterized by severe hypotension, hyponatremia, hyperkalemia, and hypoglycemia. Treatment includes immediate IV hydrocortisone (stress-dose steroids), aggressive IV normal saline for volume resuscitation, and IV dextrose if hypoglycemic. Option A would worsen hypoglycemia. Option C is too slow for a crisis. Option D — potassium is already elevated in Addison's.", "Addison's Disease", "Adrenal Crisis", ["endocrine", "addisons", "adrenal-crisis", "emergency"], "Addisonian crisis: hypotension, hyponatremia, hyperkalemia, hypoglycemia. Treat: IV hydrocortisone 100mg bolus, IV NS aggressively, IV dextrose PRN. Identify and treat trigger (infection, surgery, stress)."),

  q("Endocrine", 3, "A nurse is caring for a client post-thyroidectomy. Which assessment takes the highest priority in the immediate postoperative period?", ["Checking calcium levels daily", "Assessing for signs of airway compromise including stridor and neck swelling", "Monitoring thyroid hormone levels", "Assessing bowel sounds"], 1, "The immediate post-thyroidectomy priority is airway assessment. Potential airway complications include hemorrhage causing neck hematoma (compresses trachea), laryngeal nerve damage (causing vocal cord paralysis and stridor), and laryngospasm from hypocalcemia (damaged parathyroids). Keep an emergency tracheostomy tray and calcium gluconate at the bedside. Option A is important but not the immediate priority. Options C and D are lower priority.", "Thyroidectomy", "Post-Operative Care", ["endocrine", "thyroidectomy", "airway", "post-operative"], "Post-thyroidectomy: #1 priority = airway. Keep tracheostomy tray and IV calcium gluconate at bedside. Assess voice quality (recurrent laryngeal nerve), Chvostek/Trousseau signs (hypocalcemia), and neck for swelling."),

  q("Endocrine", 3, "A client with hyperthyroidism (Graves' disease) is prescribed methimazole. The nurse should teach the client to report:", ["Weight gain", "Sore throat, fever, or signs of infection (indicating possible agranulocytosis)", "Increased appetite", "Mild fatigue"], 1, "Methimazole (and propylthiouracil) can cause agranulocytosis — a dangerous decrease in white blood cells that impairs the immune response. Clients should immediately report sore throat, fever, mouth ulcers, or any signs of infection. CBC with differential should be monitored. Option A is expected as thyroid hormones normalize. Option C may occur. Option D is common during treatment.", "Hyperthyroidism", "Antithyroid Medication", ["endocrine", "hyperthyroidism", "methimazole", "pharmacology"], "Antithyroid drugs (methimazole, PTU): agranulocytosis is the most dangerous side effect. Report sore throat, fever, mouth sores immediately. PTU preferred in first trimester pregnancy and thyroid storm."),

  q("Endocrine", 4, "A client with pheochromocytoma is scheduled for surgery. The nurse should ensure which preoperative medication regimen is completed?", ["ACE inhibitors only", "Alpha-adrenergic blockade (phenoxybenzamine) followed by beta-blockade", "Beta-blockers first, then alpha-blockers", "Calcium channel blockers only"], 1, "Pheochromocytoma produces excess catecholamines causing severe hypertension. Preoperative preparation requires alpha-blockade FIRST (phenoxybenzamine for 10-14 days) to prevent hypertensive crisis during tumor manipulation, followed by beta-blockade for tachycardia control. NEVER give beta-blockers before alpha-blockade — unopposed alpha stimulation can cause a hypertensive crisis. Option C reverses the correct order. Options A and D are not the standard approach.", "Pheochromocytoma", "Preoperative Management", ["endocrine", "pheochromocytoma", "pharmacology", "pre-operative"], "Pheochromocytoma: alpha-block FIRST (phenoxybenzamine), THEN beta-block. Never beta-block first (unopposed alpha = hypertensive crisis). Rule of 10s: 10% bilateral, 10% malignant, 10% extra-adrenal."),

  q("Endocrine", 2, "A nurse is assessing a client with Cushing syndrome. Which assessment finding is expected?", ["Hypotension and hyperpigmentation", "Moon face, buffalo hump, truncal obesity, and purple striae", "Weight loss and heat intolerance", "Decreased blood glucose"], 1, "Cushing syndrome (cortisol excess) presents with: moon face (facial rounding), buffalo hump (dorsocervical fat pad), truncal obesity with thin extremities, purple striae, easy bruising, hyperglycemia, hypertension, osteoporosis, and immunosuppression. Option A describes Addison's disease. Option C describes hyperthyroidism. Option D — cortisol increases blood glucose.", "Cushing Syndrome", "Clinical Manifestations", ["endocrine", "cushings", "assessment", "cortisol"], "Cushing's vs Addison's: Cushing's = too much cortisol (hyperglycemia, HTN, weight gain, moon face). Addison's = too little cortisol (hypoglycemia, hypotension, weight loss, hyperpigmentation)."),

  q("Endocrine", 3, "A client with type 1 diabetes has a blood glucose of 55 mg/dL and is alert and oriented. The nurse should administer:", ["1 mg glucagon IM", "15 grams of rapid-acting carbohydrate orally", "50% dextrose IV push", "Regular insulin 5 units subcutaneously"], 1, "For conscious, alert patients with hypoglycemia, the Rule of 15 applies: give 15 grams of rapid-acting carbohydrate (4 oz juice, 3-4 glucose tablets, 1 tablespoon honey), wait 15 minutes, and recheck blood glucose. Repeat if still below 70 mg/dL. Follow with a snack containing protein and complex carbohydrate. Option A is for unconscious patients. Option C is for severe hypoglycemia with IV access. Option D would further lower glucose.", "Diabetes Management", "Hypoglycemia Treatment", ["endocrine", "diabetes", "hypoglycemia", "emergency"], "Rule of 15: 15g fast carbs, wait 15 min, recheck. If still < 70, repeat. Unconscious: glucagon IM or D50 IV. Never give oral glucose to unconscious patient (aspiration risk)."),

  q("Endocrine", 3, "A nurse is caring for a client with syndrome of inappropriate antidiuretic hormone (SIADH). Which finding is expected?", ["Hypernatremia and dehydration", "Dilutional hyponatremia with concentrated urine and fluid retention", "Polyuria and polydipsia", "Hyperkalemia"], 1, "SIADH causes excessive ADH secretion, leading to water retention, dilutional hyponatremia, decreased serum osmolality, concentrated urine (high urine specific gravity and osmolality), and fluid overload. Treatment includes fluid restriction (800-1000 mL/day), hypertonic saline for severe hyponatremia (<120 mEq/L with symptoms), and treating the underlying cause. Option A describes diabetes insipidus. Option C describes DI. Option D is not characteristic.", "SIADH", "Fluid and Electrolyte Disturbance", ["endocrine", "SIADH", "hyponatremia", "fluid-balance"], "SIADH: dilutional hyponatremia, low serum osmolality, high urine osmolality, fluid overload. Treatment: fluid restriction. DI is the opposite: high serum Na, dilute urine, dehydration."),

  q("Endocrine", 3, "A client with diabetes insipidus is prescribed desmopressin (DDAVP). The nurse should monitor for:", ["Hyperglycemia", "Water intoxication and hyponatremia from excessive water retention", "Hyperkalemia", "Metabolic acidosis"], 1, "Desmopressin is a synthetic ADH analog that promotes water reabsorption in the kidneys. Overtreatment can cause excessive water retention, leading to dilutional hyponatremia, fluid overload, and water intoxication. Monitor daily weights, I&O, serum sodium, and urine specific gravity. Option A is unrelated to DDAVP. Options C and D are not direct effects of desmopressin.", "Diabetes Insipidus", "DDAVP Therapy", ["endocrine", "diabetes-insipidus", "DDAVP", "pharmacology"], "DI treatment: DDAVP (nasal spray or injection). Monitor for water intoxication (headache, confusion, seizures). Titrate to maintain normal serum Na and UO (avoid both extremes)."),

  q("Endocrine", 3, "A nurse is caring for a client experiencing thyroid storm. Which intervention takes priority?", ["Administering radioactive iodine", "Administering IV beta-blockers to control heart rate, PTU to block hormone synthesis, and cooling measures", "Scheduling a thyroidectomy", "Administering levothyroxine"], 1, "Thyroid storm is a life-threatening hyperthyroid crisis with extreme tachycardia, hyperthermia (>104°F/40°C), agitation, and multisystem dysfunction. Treatment priorities: 1) Beta-blockers (propranolol) for rate control, 2) PTU or methimazole to block new hormone synthesis, 3) Saturated solution of potassium iodide (SSKI) to block hormone release (given 1 hour AFTER PTU), 4) Cooling measures, 5) Hydrocortisone for adrenal support. Option A is contraindicated in storm. Option C is not immediate. Option D worsens the condition.", "Thyroid Storm", "Emergency Management", ["endocrine", "thyroid-storm", "emergency", "critical-care"], "Thyroid storm treatment order: 1) Beta-blocker (propranolol), 2) PTU, 3) SSKI (1 hour after PTU), 4) Hydrocortisone, 5) Cooling (avoid aspirin — displaces T4 from binding proteins)."),

  q("Endocrine", 2, "A client with type 2 diabetes asks about the purpose of hemoglobin A1C testing. The nurse should explain:", ["It measures blood glucose at the time of the test", "It reflects average blood glucose control over the past 2-3 months", "It is used to diagnose type 1 diabetes only", "It should be checked weekly"], 1, "HbA1C measures glycosylated hemoglobin, reflecting average blood glucose over the preceding 2-3 months (lifespan of a red blood cell). Normal is <5.7%, prediabetes 5.7-6.4%, diabetes >= 6.5%. The ADA target for most diabetic adults is <7%. It is checked every 3-6 months. Option A describes a random glucose. Option C is incorrect — A1C is used for both types. Option D is too frequent.", "Diabetes Management", "HbA1C Monitoring", ["endocrine", "diabetes", "HbA1C", "lab-values"], "HbA1C: <5.7% normal, 5.7-6.4% prediabetes, >=6.5% diabetes. Target <7% for most adults. Falsely low in hemolytic anemia, blood loss. Falsely high in iron deficiency, splenectomy."),

  // ============================================================
  // MEDICAL-SURGICAL: HEMATOLOGY/ONCOLOGY (35 questions)
  // ============================================================
  q("Hematology", 3, "A nurse is caring for a client with disseminated intravascular coagulation (DIC). Which laboratory findings are characteristic?", ["Elevated fibrinogen and normal D-dimer", "Decreased fibrinogen, elevated D-dimer, prolonged PT/aPTT, and thrombocytopenia", "Elevated platelet count and decreased PT", "Normal coagulation studies with isolated anemia"], 1, "DIC involves simultaneous clotting and bleeding. Clotting factors and platelets are consumed (decreased fibrinogen, thrombocytopenia, prolonged PT/aPTT), while fibrinolysis produces elevated D-dimer and fibrin degradation products (FDPs). Treatment focuses on treating the underlying cause (sepsis, obstetric complication, malignancy) and supportive care (FFP, platelets, cryoprecipitate). Option A is the opposite. Options C and D are inconsistent with DIC.", "DIC", "Laboratory Findings", ["hematology", "DIC", "coagulation", "lab-values"], "DIC labs: everything is consumed (low platelets, low fibrinogen, prolonged PT/aPTT) and broken down (high D-dimer, high FDP). Treat the underlying cause first."),

  q("Hematology", 2, "A nurse is preparing to administer a blood transfusion. Which action is essential before starting the transfusion?", ["Warm the blood to body temperature in a microwave", "Verify the client's identity and blood type with two nurses at the bedside, comparing with the blood bank tag", "Administer diphenhydramine to all clients before transfusion", "Start the transfusion through a 24-gauge IV catheter"], 1, "Blood transfusion safety requires two-nurse verification at the bedside: check client identity (name and medical record number), blood type, Rh factor, crossmatch compatibility, unit number, and expiration date. Use at least an 18-20 gauge IV catheter and normal saline-only tubing. Option A — never use a microwave (hemolysis). Option C — premedication is not routine. Option D — gauge is too small (causes hemolysis).", "Blood Transfusion", "Safety Verification", ["hematology", "transfusion", "safety", "procedures"], "Blood transfusion: 2-nurse verification, 18-20g IV, NS only (no dextrose or LR), infuse within 4 hours, monitor VS at baseline, 15 min, 30 min, hourly, and post."),

  q("Hematology", 3, "A client receiving chemotherapy develops a temperature of 38.5°C and an absolute neutrophil count (ANC) of 400 cells/mm3. The nurse recognizes this as:", ["A normal finding during chemotherapy", "Febrile neutropenia requiring immediate empiric antibiotic therapy", "A mild infection requiring oral antibiotics only", "An allergic reaction to chemotherapy"], 1, "Febrile neutropenia (temperature >=38.3°C single reading or >=38.0°C for >1 hour + ANC <500 cells/mm3) is a medical emergency. Infection can progress rapidly without neutrophils. Blood cultures should be drawn and empiric broad-spectrum IV antibiotics (anti-pseudomonal coverage) started within 1 hour. Option A minimizes a dangerous condition. Option C underestimates severity. Option D is a different complication.", "Chemotherapy", "Febrile Neutropenia", ["hematology", "oncology", "neutropenia", "infection"], "Febrile neutropenia: ANC < 500 + fever. Blood cultures x 2, then IV antibiotics within 1 hour. Do not wait for culture results. Neutropenic precautions: no fresh flowers, no raw fruits/vegetables."),

  q("Hematology", 3, "A client with iron deficiency anemia is prescribed ferrous sulfate. The nurse should teach the client to take it:", ["With milk and antacids for better absorption", "On an empty stomach with vitamin C (orange juice) to enhance absorption", "At the same time as calcium supplements", "Only at bedtime with a large meal"], 1, "Iron absorption is enhanced by vitamin C (ascorbic acid) and an acidic environment. Take on an empty stomach 1 hour before or 2 hours after meals. Avoid concurrent use of antacids, calcium, milk, tea, and coffee (reduce absorption). Side effects include dark stools, constipation, and GI upset. If GI upset is intolerable, take with food but absorption decreases. Option A reduces absorption. Option C — calcium interferes. Option D is not optimal.", "Iron Deficiency Anemia", "Iron Supplementation", ["hematology", "anemia", "iron", "pharmacology"], "Oral iron: take with vitamin C (OJ), on empty stomach. Liquid iron: use straw (stains teeth). Dark stools are expected. Constipation common — increase fiber and fluids. Absorption inhibitors: antacids, calcium, tea."),

  q("Hematology", 4, "A client with acute lymphoblastic leukemia (ALL) starts chemotherapy. The nurse monitors for tumor lysis syndrome (TLS). Which laboratory findings indicate TLS?", ["Hypocalcemia, hyperkalemia, hyperuricemia, and hyperphosphatemia", "Hypercalcemia and hypokalemia", "Normal electrolytes with elevated WBC", "Hypoglycemia and metabolic alkalosis"], 0, "Tumor lysis syndrome occurs when rapid cancer cell destruction releases intracellular contents: potassium (hyperkalemia), phosphorus (hyperphosphatemia), uric acid (hyperuricemia), and nucleic acids. Phosphorus binds calcium, causing secondary hypocalcemia. These electrolyte imbalances can cause cardiac dysrhythmias, renal failure, and seizures. Prevention includes IV hydration, allopurinol or rasburicase. Option B is the opposite. Options C and D are not TLS findings.", "Tumor Lysis Syndrome", "Prevention and Recognition", ["hematology", "oncology", "TLS", "electrolytes"], "TLS: hyperkalemia, hyperphosphatemia, hyperuricemia, hypocalcemia. Prevention: aggressive IV hydration, allopurinol (prevents uric acid formation), rasburicase (breaks down uric acid). Monitor q4-6h."),

  q("Hematology", 3, "A nurse is caring for a client with sickle cell crisis. Which intervention is the priority?", ["Restricting IV fluids", "Aggressive IV hydration and pain management", "Applying ice packs to painful areas", "Encouraging exercise during the crisis"], 1, "Sickle cell crisis (vaso-occlusive crisis) causes tissue ischemia and severe pain. Priorities include aggressive IV hydration (3-5 L/day to reduce blood viscosity and prevent further sickling), effective pain management (IV opioids — often patient-controlled analgesia), oxygen therapy if SpO2 < 95%, and monitoring for complications (acute chest syndrome, stroke, splenic sequestration). Option A worsens sickling. Option C — use warm compresses, not ice (cold promotes sickling). Option D worsens pain.", "Sickle Cell Disease", "Crisis Management", ["hematology", "sickle-cell", "pain-management", "hydration"], "Sickle cell crisis: IV fluids (dilute blood, reduce viscosity) + IV opioids (PCA). Apply WARMTH (not cold). Acute chest syndrome: fever + chest pain + pulmonary infiltrate — #1 cause of death in SCD."),

  q("Hematology", 2, "A nurse is teaching a client receiving warfarin about dietary considerations. The client should be advised to:", ["Avoid all green vegetables entirely", "Maintain a consistent daily intake of vitamin K-containing foods", "Increase vitamin K intake when INR is low", "Take additional vitamin K supplements with warfarin"], 1, "Warfarin works by inhibiting vitamin K-dependent clotting factors. Dramatic changes in vitamin K intake (from green leafy vegetables) alter the drug's effectiveness. Clients should maintain a CONSISTENT (not eliminated) intake of vitamin K foods. This allows for stable INR control with appropriate warfarin dosing. Option A eliminates important nutrition. Option C would further reduce INR. Option D would antagonize warfarin.", "Anticoagulation Therapy", "Warfarin and Vitamin K", ["hematology", "warfarin", "vitamin-K", "patient-education"], "Warfarin + vitamin K: consistency is key, not avoidance. High vitamin K foods: kale, spinach, broccoli, Brussels sprouts. INR target: 2.0-3.0 (most indications)."),

  q("Hematology", 3, "A client develops heparin-induced thrombocytopenia (HIT). The nurse should expect which change in anticoagulation therapy?", ["Switch to a higher dose of heparin", "Discontinue all heparin products and switch to a direct thrombin inhibitor such as argatroban", "Administer protamine sulfate", "Switch to low molecular weight heparin", "Switch to warfarin immediately"], 1, "HIT is an immune-mediated reaction where antibodies against heparin-platelet factor 4 complexes cause thrombocytopenia AND paradoxical thrombosis. ALL heparin products must be discontinued (including flushes). Alternative anticoagulation with a direct thrombin inhibitor (argatroban, bivalirudin) is started. LMWH cannot be substituted (cross-reactivity). Warfarin should not be started until platelets recover. Option A worsens HIT. Option C is the heparin antidote, not for HIT. Option D has cross-reactivity.", "Heparin-Induced Thrombocytopenia", "Management", ["hematology", "HIT", "anticoagulation", "pharmacology"], "HIT: platelet drop >50% from baseline + thrombosis. Stop ALL heparin (including flushes). Start argatroban or bivalirudin. No LMWH (cross-reacts). No warfarin until platelets >150,000."),

  q("Hematology", 3, "A nurse is caring for a client with lymphoma who develops superior vena cava syndrome. Which assessment finding is expected?", ["Lower extremity edema", "Facial and upper extremity edema, JVD, and dyspnea", "Abdominal distension with ascites", "Pedal edema only"], 1, "Superior vena cava (SVC) syndrome occurs when a mediastinal tumor compresses the SVC, obstructing venous return from the head, neck, and upper extremities. Signs include facial/periorbital edema (worse in the morning), upper extremity edema, JVD, dyspnea, and plethora (reddish-purple skin of face/neck). This is an oncologic emergency. Option A is lower body venous obstruction. Options C and D are not characteristic of SVC syndrome.", "Oncologic Emergencies", "SVC Syndrome", ["hematology", "oncology", "SVC-syndrome", "emergency"], "SVC syndrome: facial edema, dyspnea, JVD, upper body edema. Oncologic emergency. Elevate HOB, administer oxygen. Treatment: radiation, stenting, or chemotherapy depending on tumor type."),

  q("Hematology", 2, "A client with aplastic anemia has a platelet count of 18,000/mm3. The nurse should implement:", ["Strict isolation precautions", "Bleeding precautions including soft toothbrush, electric razor, no IM injections, and fall prevention", "Aggressive physical therapy", "Blood glucose monitoring every 2 hours"], 1, "A platelet count below 20,000/mm3 places the client at high risk for spontaneous bleeding. Bleeding precautions include: soft-bristle toothbrush, electric razor (no straight razors), no IM injections, no aspirin/NSAIDs, avoid Valsalva maneuver, apply prolonged pressure to venipuncture sites, fall prevention, and monitoring for signs of internal bleeding. Option A is for neutropenia. Options C and D are not the priority concern.", "Aplastic Anemia", "Bleeding Precautions", ["hematology", "thrombocytopenia", "bleeding", "safety"], "Platelet thresholds: <150,000 = thrombocytopenia, <50,000 = bleeding risk with procedures, <20,000 = spontaneous bleeding risk, <10,000 = spontaneous CNS/GI bleeding risk. Transfuse at <10,000 or active bleeding."),

  // ============================================================
  // MEDICAL-SURGICAL: MUSCULOSKELETAL (35 questions)
  // ============================================================
  q("Musculoskeletal", 3, "A nurse is assessing a client with a new cast on the right arm. The client reports increasing pain unrelieved by prescribed analgesics, tingling, and pallor of the fingers. The nurse suspects:", ["Normal post-fracture pain", "Compartment syndrome requiring immediate intervention", "Carpal tunnel syndrome", "Tendonitis"], 1, "The 5 P's of compartment syndrome: Pain (out of proportion, unrelieved by analgesics, worst with passive stretch), Paresthesia, Pallor, Pulselessness, and Paralysis. Pain out of proportion to the injury is the EARLIEST sign. This is a surgical emergency — the nurse must notify the provider immediately. The cast may need to be bivalved (cut in half) or a fasciotomy performed. Options A, C, and D are not surgical emergencies.", "Compartment Syndrome", "Recognition", ["musculoskeletal", "compartment-syndrome", "cast-care", "emergency"], "Compartment syndrome: pain out of proportion is EARLIEST sign. Pain with PASSIVE stretch is key finding. Pressure > 30 mmHg = fasciotomy. Do NOT elevate the limb above the heart (reduces perfusion)."),

  q("Musculoskeletal", 2, "A nurse is teaching a client with osteoporosis about bisphosphonate therapy (alendronate). Which instruction is essential?", ["Take with food for better absorption", "Take on an empty stomach with a full glass of water and remain upright for at least 30 minutes", "Take at bedtime lying down", "Take with calcium supplements at the same time"], 1, "Alendronate must be taken on an empty stomach (first thing in the morning) with a full glass (8 oz) of plain water. The client must remain upright (sitting or standing) for at least 30 minutes to prevent esophageal erosion and ulceration. Wait 30 minutes before eating, drinking, or taking other medications. Option A reduces absorption. Option C risks esophageal damage. Option D interferes with absorption.", "Osteoporosis", "Bisphosphonate Therapy", ["musculoskeletal", "osteoporosis", "pharmacology", "patient-education"], "Bisphosphonates: empty stomach, full glass of water, upright 30 min, wait before other meds/food. Risk: osteonecrosis of the jaw (dental exam before starting), atypical femoral fractures (long-term use)."),

  q("Musculoskeletal", 3, "A client with a hip fracture is scheduled for open reduction internal fixation (ORIF). The nurse should position the client postoperatively with:", ["The affected leg in external rotation", "The affected leg in abduction using an abduction pillow", "The affected leg in adduction and flexion >90 degrees", "No specific positioning required"], 1, "Post-hip ORIF, the affected leg must be maintained in abduction (away from midline) to prevent dislocation. An abduction pillow or pillows between the legs maintain alignment. Avoid adduction (crossing legs), internal rotation, and hip flexion >90 degrees. Use a raised toilet seat and avoid low chairs. Option A (external rotation) is not the correct position. Option C violates hip precautions. Option D ignores essential positioning.", "Hip Fracture", "Post-Operative Positioning", ["musculoskeletal", "hip-fracture", "positioning", "post-operative"], "Hip precautions: no hip flexion >90°, no adduction (crossing legs), no internal rotation. Use abduction pillow, raised toilet seat, reach extender. Log-roll for repositioning."),

  q("Musculoskeletal", 2, "A nurse is teaching a client about crutch walking with a three-point gait. The nurse should instruct the client to:", ["Advance both crutches with the unaffected leg first", "Advance both crutches and the affected leg simultaneously, then the unaffected leg", "Move the right crutch and left leg simultaneously", "Hop on both legs together"], 1, "Three-point gait is used for non-weight-bearing or partial-weight-bearing on one leg. Both crutches and the affected leg advance together, followed by the unaffected leg stepping through. This distributes weight through the crutches, protecting the affected extremity. Option A reverses the pattern. Option C describes a four-point or two-point gait. Option D is unsafe.", "Mobility Aids", "Crutch Walking", ["musculoskeletal", "mobility", "crutches", "patient-education"], "Crutch gait types: 3-point (non-weight bearing), 2-point (partial weight bearing, alternating), 4-point (most stable, maximum support). Going upstairs: good leg first. Downstairs: crutches and bad leg first."),

  q("Musculoskeletal", 3, "A client with rheumatoid arthritis is prescribed methotrexate. The nurse should monitor for which serious adverse effect?", ["Weight gain", "Hepatotoxicity and bone marrow suppression", "Hyperglycemia", "Hypertension"], 1, "Methotrexate is an immunosuppressant/DMARD used for RA. Serious adverse effects include hepatotoxicity (monitor liver enzymes), bone marrow suppression (monitor CBC — leukopenia, thrombocytopenia, anemia), pneumonitis, and teratogenicity (absolutely contraindicated in pregnancy). Folic acid supplementation reduces side effects. Option A is not associated. Options C and D are not primary concerns.", "Rheumatoid Arthritis", "DMARD Therapy", ["musculoskeletal", "rheumatoid-arthritis", "methotrexate", "pharmacology"], "Methotrexate: monitor LFTs and CBC regularly. Give folic acid daily to reduce side effects. Absolutely contraindicated in pregnancy (category X). Avoid alcohol. Report mouth sores, bleeding, jaundice."),

  q("Musculoskeletal", 3, "A nurse is caring for a client in skeletal traction. Which finding indicates a complication?", ["Weights hanging freely", "Pin site with serous drainage and mild erythema", "Pin site with purulent drainage, increasing pain, and warmth", "Slight pulling sensation at the traction site"], 2, "Purulent drainage, increasing pain, and warmth at pin sites indicate infection — a significant complication of skeletal traction. The nurse should perform pin care per protocol, assess vital signs for systemic infection, and notify the provider for possible culture and antibiotic therapy. Option A is correct functioning. Option B (serous drainage) is normal. Option D is expected with traction.", "Skeletal Traction", "Pin Site Complications", ["musculoskeletal", "traction", "pin-care", "infection"], "Pin care: clean per protocol (usually with normal saline), assess for infection (purulent drainage, erythema, warmth, odor). Never remove weights, maintain alignment, check neurovascular status q2-4h."),

  q("Musculoskeletal", 3, "A client with a below-knee amputation is 3 days postoperative. The nurse should encourage:", ["Keeping the residual limb elevated on pillows at all times", "Keeping the residual limb flat on the bed and prone positioning to prevent hip flexion contracture", "Dangling the residual limb over the bed edge to promote circulation", "Tight bandaging with no rewrapping", "Immediate weight bearing"], 1, "To prevent hip and knee flexion contractures, the residual limb should not be elevated on pillows after the first 24 hours. Prone positioning for 20-30 minutes several times daily stretches the hip flexors. The residual limb is wrapped in a figure-8 pattern (rewrapped every 4-8 hours) to shape it for prosthesis fitting. Option A promotes contracture after initial period. Option C can cause dependent edema. Option D — rewrapping is necessary.", "Amputation", "Post-Operative Care", ["musculoskeletal", "amputation", "contracture-prevention", "post-operative"], "Post-amputation: prevent contractures (no pillow under knee/hip after 24 hrs), prone positioning, figure-8 wrapping (proximal to distal), phantom limb pain is real (treat with mirror therapy, gabapentin)."),

  q("Musculoskeletal", 4, "A client with systemic lupus erythematosus (SLE) develops a butterfly rash across the cheeks and nose. The nurse should also assess for:", ["Isolated skin involvement only", "Renal involvement (lupus nephritis) by monitoring protein in urine and serum creatinine", "Bacterial skin infection", "Hyperthyroidism"], 1, "SLE is a systemic autoimmune disease affecting multiple organ systems. Lupus nephritis occurs in up to 50% of SLE patients and is a major cause of morbidity. The nurse should monitor urinalysis for proteinuria and hematuria, serum creatinine, BUN, and complement levels (C3, C4). Other complications include pericarditis, pleuritis, cerebritis, and cytopenias. Option A underestimates systemic nature. Option C is not the primary concern. Option D is unrelated.", "Systemic Lupus Erythematosus", "Renal Complications", ["musculoskeletal", "SLE", "lupus-nephritis", "autoimmune"], "SLE: butterfly rash is classic but renal involvement determines prognosis. Monitor: urinalysis, creatinine, anti-dsDNA (correlates with disease activity), complement levels. Avoid sun exposure (photosensitivity)."),

  q("Musculoskeletal", 2, "A nurse is teaching a client with gout about dietary modifications. The client should be advised to avoid:", ["All fruits and vegetables", "High-purine foods such as organ meats, shellfish, and alcohol", "Dairy products", "All grains"], 1, "Gout is caused by uric acid crystal deposition in joints. High-purine foods increase uric acid production. Foods to avoid: organ meats (liver, kidney), shellfish, red meat, beer/liquor, and high-fructose corn syrup. Low-fat dairy, cherries, and adequate hydration may help reduce uric acid levels. Allopurinol or febuxostat reduce uric acid production. Option A eliminates nutritious foods. Options C and D are not high in purines.", "Gout", "Dietary Management", ["musculoskeletal", "gout", "nutrition", "uric-acid"], "Gout diet: avoid organ meats, shellfish, red meat, beer, HFCS. Encourage: low-fat dairy, cherries, water (>2L/day). Acute treatment: colchicine, NSAIDs (indomethacin). Chronic: allopurinol, febuxostat."),

  // ============================================================
  // MEDICAL-SURGICAL: IMMUNOLOGY (35 questions)
  // ============================================================
  q("Immunological", 3, "A nurse is caring for a client in anaphylactic shock. The first medication to administer is:", ["IV diphenhydramine", "IM epinephrine in the mid-outer thigh", "IV methylprednisolone", "Inhaled albuterol"], 1, "Epinephrine is the first-line drug for anaphylaxis — it reverses bronchospasm, increases blood pressure, and reduces mucosal edema. Administer IM in the mid-outer thigh (vastus lateralis) using a 1:1000 concentration (0.3-0.5 mg for adults). Repeat every 5-15 minutes if needed. IV epinephrine (1:10,000) is reserved for cardiovascular collapse. Diphenhydramine and corticosteroids are adjunctive therapies, not first-line. Option D is insufficient alone.", "Anaphylaxis", "Emergency Management", ["immunology", "anaphylaxis", "epinephrine", "emergency"], "Anaphylaxis treatment order: 1) IM epinephrine (1:1,000), 2) Call for help, 3) Position supine with legs elevated, 4) IV NS bolus, 5) Diphenhydramine, 6) Methylprednisolone. Repeat epi q5-15min PRN."),

  q("Immunological", 2, "A nurse is teaching a client newly diagnosed with HIV about medication adherence. The nurse should emphasize:", ["Taking antiretroviral medications only when feeling ill", "Greater than 95% adherence to antiretroviral therapy is necessary to suppress viral load", "Medications can be discontinued once the viral load is undetectable", "Antiretroviral therapy is optional"], 1, "Antiretroviral therapy (ART) requires >95% adherence to maintain viral suppression, prevent drug resistance, and reduce transmission. Missing even a few doses can allow viral replication and development of resistant strains. ART is lifelong — an undetectable viral load does not mean the virus is gone. Option A leads to drug resistance. Option C allows viral rebound. Option D is medically incorrect.", "HIV/AIDS", "Medication Adherence", ["immunology", "HIV", "antiretroviral", "patient-education"], "ART adherence: >95% required for viral suppression. Set reminders, use pill organizers. Undetectable = untransmittable (U=U) but continue medications. Monitor CD4 count and viral load regularly."),

  q("Immunological", 3, "A nurse is caring for a client who received a kidney transplant and is on immunosuppressive therapy. Which finding requires immediate attention?", ["Mild muscle aches", "Temperature of 38.3°C with a productive cough", "Slight fatigue", "Increased appetite"], 1, "Immunosuppressed transplant recipients are at high risk for opportunistic infections. A temperature of 38.3°C (101°F) with a productive cough in an immunocompromised client may indicate pneumonia or other serious infection requiring prompt evaluation and treatment. Signs of infection may be blunted by immunosuppression. Option A may be a medication side effect. Options C and D are non-specific.", "Organ Transplant", "Infection Risk", ["immunology", "transplant", "immunosuppression", "infection"], "Post-transplant immunosuppression: report ANY fever, sore throat, or signs of infection immediately. Avoid crowds, live vaccines, sick contacts. Monitor for CMV, EBV, and fungal infections."),

  q("Immunological", 3, "A client with systemic lupus erythematosus (SLE) is prescribed hydroxychloroquine. The nurse should teach the client about which important monitoring requirement?", ["Weekly blood pressure checks", "Regular ophthalmologic examinations to monitor for retinal toxicity", "Monthly chest X-rays", "Daily urine glucose testing"], 1, "Hydroxychloroquine can cause irreversible retinal damage (bull's eye maculopathy) with long-term use. The American Academy of Ophthalmology recommends baseline eye exam, then annual screening after 5 years (or sooner with risk factors). The client should report any visual changes immediately. Options A, C, and D are not specific monitoring requirements for hydroxychloroquine.", "SLE", "Hydroxychloroquine Monitoring", ["immunology", "SLE", "hydroxychloroquine", "pharmacology"], "Hydroxychloroquine: eye exam at baseline, then annual after 5 years. Risk increases with dose >5 mg/kg/day and renal impairment. Report blurred vision, blind spots, or color changes immediately."),

  q("Immunological", 2, "A nurse is teaching a client about standard precautions. Which statement indicates correct understanding?", ["Standard precautions are only needed for clients with known infections", "Standard precautions are used with all clients regardless of diagnosis to prevent transmission of blood-borne pathogens", "Gloves are only needed when touching wounds", "Hand hygiene is optional if gloves are worn"], 1, "Standard precautions apply to ALL clients regardless of known or suspected infection status. They protect against blood-borne pathogen transmission and include: hand hygiene, PPE use (gloves, gowns, masks, eye protection as appropriate), safe injection practices, respiratory hygiene/cough etiquette, and proper handling of contaminated equipment. Option A is incorrect — precautions are universal. Option C underestimates PPE needs. Option D — hand hygiene is always required.", "Infection Control", "Standard Precautions", ["immunology", "infection-control", "PPE", "safety"], "Standard precautions = for ALL patients. Transmission-based precautions: Contact (MRSA, C.diff), Droplet (flu, pertussis), Airborne (TB, measles, varicella — N95 mask required)."),

  q("Immunological", 3, "A client with a latex allergy is scheduled for surgery. The nurse should ensure:", ["Standard surgical gloves are used", "The client is scheduled as the first case of the day in a latex-free environment", "Latex-containing products can be used if the client takes antihistamines", "No special precautions are needed if the allergy is mild"], 1, "Clients with latex allergy should be scheduled as the first case of the day to minimize residual latex particles in the air from previous surgeries. A completely latex-free environment must be prepared with non-latex gloves, catheters, IV tubing ports, and equipment. Cross-reactive foods include bananas, avocados, kiwi, and chestnuts. Option A uses latex gloves. Option C does not prevent anaphylaxis. Option D risks a severe reaction.", "Latex Allergy", "Surgical Precautions", ["immunology", "latex-allergy", "surgery", "safety"], "Latex allergy: first case of the day, latex-free environment. Cross-reactive foods: banana, avocado, kiwi, chestnut. Healthcare workers at highest risk due to repeated exposure."),

  q("Immunological", 3, "A nurse is caring for a client with neutropenia (ANC 800/mm3). Which precaution should be implemented?", ["Allow fresh flowers in the room for the client's comfort", "Neutropenic precautions: avoid fresh fruits, vegetables, and flowers; strict hand hygiene; limit visitors", "No restrictions are needed for this ANC level", "Airborne isolation precautions"], 1, "Neutropenic precautions protect immunocompromised clients from infection. Fresh flowers and plants harbor Aspergillus. Raw/uncooked foods may contain bacteria. Strict hand hygiene is the single most effective infection prevention measure. Limit visitors and screen for illness. Avoid rectal temperatures and invasive procedures. Option A introduces infection risk. Option C ignores infection risk. Option D is for airborne pathogens, not neutropenia.", "Neutropenia", "Protective Precautions", ["immunology", "neutropenia", "infection-prevention", "safety"], "Neutropenic precautions: ANC < 1000. No fresh flowers/plants, no raw foods, strict hand hygiene, private room, limit visitors, avoid crowds, no rectal temps, daily mouth care with soft brush."),

  q("Immunological", 4, "A client develops graft-versus-host disease (GVHD) after a bone marrow transplant. The nurse should monitor for:", ["Isolated skin rash only", "Skin rash, hepatic dysfunction (elevated bilirubin), and profuse watery diarrhea", "Bone pain only", "Elevated WBC count"], 1, "GVHD occurs when donor immune cells attack the recipient's tissues. The three primary target organs are skin (maculopapular rash), liver (elevated bilirubin, hepatomegaly), and GI tract (severe watery diarrhea, abdominal cramping). Treatment includes immunosuppressive therapy (corticosteroids, cyclosporine). Option A is incomplete. Option C is associated with engraftment. Option D would be a positive finding.", "Bone Marrow Transplant", "GVHD", ["immunology", "GVHD", "transplant", "complications"], "GVHD target organs: Skin (rash), Liver (jaundice, elevated LFTs), GI (diarrhea 1-2 L/day). Acute GVHD: within 100 days. Chronic GVHD: after 100 days. Treatment: immunosuppression."),

  // ============================================================
  // PHARMACOLOGY (150 questions)
  // ============================================================
  q("Pharmacology", 2, "A nurse is preparing to administer digoxin. The nurse should hold the medication and notify the provider if the client's heart rate is:", ["72 bpm", "Below 60 bpm", "80 bpm", "68 bpm"], 1, "Digoxin is a cardiac glycoside that slows the heart rate. The nurse must check the apical pulse for a full minute before administration. Hold digoxin and notify the provider if the heart rate is below 60 bpm (adults) or below 70-90 bpm (children, depending on age). Also monitor for signs of toxicity: nausea, vomiting, visual disturbances (yellow-green halos), and cardiac dysrhythmias. Check potassium — hypokalemia increases digoxin toxicity risk.", "Cardiac Glycosides", "Digoxin Administration", ["pharmacology", "digoxin", "cardiac", "medication-safety"], "Digoxin: check apical pulse x 1 full minute. Hold if < 60 bpm. Therapeutic level: 0.5-2.0 ng/mL. Toxicity signs: nausea, visual changes (yellow-green halos), bradycardia. Hypokalemia increases toxicity."),

  q("Pharmacology", 3, "A client is prescribed lisinopril. The nurse should monitor for which common adverse effect?", ["Hyperglycemia", "Dry, persistent cough", "Weight gain", "Tachycardia"], 1, "ACE inhibitors (ending in '-pril': lisinopril, enalapril, captopril) commonly cause a dry, persistent cough due to accumulation of bradykinin. This occurs in 5-20% of patients and may require switching to an ARB (angiotensin receptor blocker, ending in '-sartan'). Other adverse effects include hyperkalemia, angioedema, first-dose hypotension, and teratogenicity. Options A, C, and D are not common ACE inhibitor effects.", "ACE Inhibitors", "Adverse Effects", ["pharmacology", "ACE-inhibitors", "lisinopril", "adverse-effects"], "ACE inhibitors: dry cough (switch to ARB), hyperkalemia (monitor K+), angioedema (discontinue immediately), first-dose hypotension (give first dose at bedtime), contraindicated in pregnancy."),

  q("Pharmacology", 3, "A nurse is administering IV potassium chloride. Which safety measure is essential?", ["Administer by IV push for rapid correction", "Always dilute and administer via infusion pump at no more than 10-20 mEq/hour", "Mix with dextrose solutions only", "Administer undiluted in a peripheral vein"], 1, "IV potassium chloride must NEVER be given by IV push (can cause fatal cardiac arrest). It must be diluted (typically 20-40 mEq/L) and administered via infusion pump at a rate not exceeding 10-20 mEq/hour. Monitor ECG during rapid infusion. Assess IV site for infiltration (KCl is a vesicant). Option A is lethal. Option C — can be mixed with NS or D5W. Option D causes severe phlebitis.", "Electrolyte Replacement", "IV Potassium Safety", ["pharmacology", "potassium", "IV-safety", "medication-safety"], "IV KCl: NEVER push, ALWAYS dilute, use infusion pump, max 10-20 mEq/hr, monitor ECG, assess IV site (vesicant). Cardiac monitor required for rates >10 mEq/hr."),

  q("Pharmacology", 2, "A client is started on metformin for type 2 diabetes. The nurse should teach the client about which serious adverse effect?", ["Hypoglycemia as a primary concern", "Lactic acidosis, especially with renal impairment or contrast dye exposure", "Significant weight gain", "Hyperkalemia"], 1, "Metformin's most serious adverse effect is lactic acidosis, which is rare but potentially fatal. Risk increases with renal impairment (check eGFR before starting), hepatic impairment, excessive alcohol use, and iodinated contrast dye exposure (hold metformin 48 hours before and after contrast). Common side effects include GI upset and diarrhea. Option A — metformin rarely causes hypoglycemia as monotherapy. Option C — metformin is weight-neutral or causes weight loss. Option D is unrelated.", "Oral Hypoglycemics", "Metformin", ["pharmacology", "metformin", "diabetes", "lactic-acidosis"], "Metformin: hold 48 hrs before/after IV contrast (lactic acidosis risk). Check eGFR (contraindicated if < 30). GI side effects common (take with food). Does NOT cause hypoglycemia as monotherapy."),

  q("Pharmacology", 3, "A nurse is teaching a client about the anticoagulant rivaroxaban (Xarelto). Which statement indicates correct understanding?", ["I need regular INR monitoring with this medication", "This medication does not require routine coagulation monitoring, but I should report unusual bleeding", "I can take aspirin freely with this medication", "This medication requires vitamin K dietary restrictions"], 1, "Direct oral anticoagulants (DOACs) like rivaroxaban do not require routine coagulation monitoring (unlike warfarin, which requires INR). However, patients must be educated to report signs of bleeding. There is no specific dietary restriction (vitamin K does not affect DOACs). Reversal agent for rivaroxaban/apixaban is andexanet alfa. Option A applies to warfarin. Option C increases bleeding risk. Option D applies to warfarin.", "Anticoagulant Therapy", "DOAC Education", ["pharmacology", "DOAC", "rivaroxaban", "anticoagulation"], "DOACs vs warfarin: no INR monitoring, no dietary restrictions, fewer drug interactions, predictable dosing. Reversal agents: andexanet alfa (rivaroxaban/apixaban), idarucizumab (dabigatran)."),

  q("Pharmacology", 4, "A client is prescribed vancomycin IV. The nurse should administer this medication:", ["By rapid IV push over 5 minutes", "Over at least 60 minutes to prevent red man syndrome", "As a continuous drip at maximum rate", "IM for fastest onset"], 1, "Vancomycin must be infused slowly over at least 60 minutes (some protocols recommend 1 g over 90-120 minutes). Rapid infusion causes Red Man Syndrome (histamine release causing flushing, rash, pruritus, and hypotension of the face, neck, and trunk — NOT a true allergy). Monitor trough levels (15-20 mcg/mL for serious infections). Also monitor renal function and ototoxicity. Option A causes Red Man Syndrome. Option C is too fast. Option D is too irritating for IM.", "Antibiotics", "Vancomycin Administration", ["pharmacology", "vancomycin", "IV-administration", "red-man-syndrome"], "Vancomycin: infuse over 60+ min (prevent Red Man Syndrome). Trough: 15-20 mcg/mL. Monitor: renal function (nephrotoxic), hearing (ototoxic). Red Man Syndrome = histamine reaction, not true allergy."),

  q("Pharmacology", 3, "A client on phenytoin therapy has a serum level of 28 mcg/mL. The nurse should:", ["Continue the medication as prescribed", "Hold the medication and notify the provider of the toxic level", "Increase the dose for better seizure control", "Administer an additional loading dose"], 1, "Therapeutic phenytoin level is 10-20 mcg/mL. A level of 28 mcg/mL is toxic. Signs of toxicity include nystagmus (first sign at 20 mcg/mL), ataxia, slurred speech, confusion, and at very high levels, cardiac dysrhythmias. The medication should be held and the provider notified. Options A, C, and D would worsen toxicity.", "Anticonvulsants", "Phenytoin Toxicity", ["pharmacology", "phenytoin", "toxicity", "therapeutic-drug-monitoring"], "Phenytoin: therapeutic 10-20 mcg/mL. Toxicity signs by level: >20 = nystagmus, >30 = ataxia, >40 = lethargy. Zero-order kinetics: small dose changes cause large level changes. Many drug interactions."),

  q("Pharmacology", 2, "A nurse is administering insulin. Which insulin type has the most rapid onset of action?", ["NPH insulin", "Insulin lispro (Humalog)", "Regular insulin", "Insulin glargine (Lantus)"], 1, "Rapid-acting insulins (lispro/Humalog, aspart/NovoLog, glulisine/Apidra) have onset in 10-15 minutes, peak at 1-2 hours, and duration of 3-5 hours. Regular insulin has onset 30-60 minutes. NPH has onset 2-4 hours. Glargine is long-acting with no peak and 24-hour duration. Rapid-acting must be given immediately before (or within 15 minutes of) meals.", "Insulin", "Types and Timing", ["pharmacology", "insulin", "diabetes", "medication-administration"], "Insulin onset: Rapid (lispro/aspart) = 10-15 min. Regular = 30-60 min. NPH = 2-4 hr. Glargine = 1-2 hr (no peak, 24 hr). NEVER mix glargine or detemir with other insulins."),

  q("Pharmacology", 3, "A client is prescribed amlodipine for hypertension. The nurse should advise the client to avoid:", ["Dairy products", "Grapefruit juice, which can increase medication levels and side effects", "All citrus fruits", "Potassium-rich foods"], 1, "Grapefruit juice inhibits CYP3A4 enzymes in the gut wall and liver, significantly increasing the bioavailability of many calcium channel blockers (amlodipine, felodipine, nifedipine). This can cause excessive vasodilation, severe hypotension, and tachycardia. Other drug classes affected by grapefruit include statins, cyclosporine, and some benzodiazepines. Options A, C (other citrus), and D are not interactions.", "Calcium Channel Blockers", "Drug-Food Interactions", ["pharmacology", "CCB", "grapefruit-interaction", "drug-food"], "Grapefruit interaction drugs: CCBs, statins (simvastatin, atorvastatin), cyclosporine, some benzos. Mechanism: inhibits CYP3A4, increasing drug levels. Even small amounts can have significant effects."),

  q("Pharmacology", 3, "A nurse is caring for a client receiving aminoglycoside therapy (gentamicin). Which adverse effects should be monitored?", ["Hepatotoxicity and hyperglycemia", "Nephrotoxicity and ototoxicity", "Pulmonary fibrosis", "Stevens-Johnson syndrome"], 1, "Aminoglycosides (gentamicin, tobramycin, amikacin) are nephrotoxic and ototoxic. Monitor: serum creatinine, BUN, and urine output (nephrotoxicity); hearing changes, tinnitus, and vertigo (ototoxicity — may be irreversible). Monitor peak and trough levels. Ensure adequate hydration. Avoid concurrent use of other nephrotoxic/ototoxic drugs. Options A, C, and D are not primary aminoglycoside concerns.", "Antibiotics", "Aminoglycoside Monitoring", ["pharmacology", "aminoglycosides", "nephrotoxicity", "ototoxicity"], "Aminoglycosides: monitor peak (efficacy) and trough (toxicity). Nephrotoxicity: rising creatinine, decreased UO. Ototoxicity: tinnitus, hearing loss (may be irreversible), vertigo. Keep patient well hydrated."),

  q("Pharmacology", 2, "A client is prescribed atorvastatin (Lipitor). The nurse should instruct the client to report:", ["Increased energy levels", "Unexplained muscle pain, tenderness, or weakness (potential rhabdomyolysis)", "Improved appetite", "Weight loss"], 1, "Statins can cause myopathy ranging from mild myalgia to life-threatening rhabdomyolysis (skeletal muscle breakdown). Report unexplained muscle pain, tenderness, or weakness immediately. Monitor CK levels if symptoms develop. Risk increases with higher doses, combination with fibrates or niacin, and CYP3A4 inhibitors. Also monitor liver function tests. Options A, C, and D are not adverse effects requiring reporting.", "Antilipemics", "Statin Adverse Effects", ["pharmacology", "statins", "rhabdomyolysis", "adverse-effects"], "Statin monitoring: report muscle pain immediately (CK level). LFTs at baseline and PRN. Take at bedtime (cholesterol synthesis peaks at night, though atorvastatin/rosuvastatin can be taken anytime). Grapefruit interaction."),

  q("Pharmacology", 3, "A client is receiving IV heparin. Which medication should be readily available as the antidote?", ["Vitamin K", "Protamine sulfate", "Naloxone", "Flumazenil"], 1, "Protamine sulfate is the specific antidote for heparin. It binds to heparin and neutralizes its anticoagulant effect. Dosing is based on the amount of heparin given and time since last dose (1 mg protamine per 100 units of heparin in the previous 2-3 hours). Administer slowly to avoid hypotension and bradycardia. Option A (vitamin K) reverses warfarin. Option C (naloxone) reverses opioids. Option D (flumazenil) reverses benzodiazepines.", "Anticoagulant Therapy", "Heparin Reversal", ["pharmacology", "heparin", "antidote", "protamine"], "Antidote pairs: Heparin = protamine sulfate. Warfarin = vitamin K (phytonadione). Benzodiazepines = flumazenil. Opioids = naloxone. Acetaminophen = N-acetylcysteine. Digoxin = digoxin immune Fab."),

  q("Pharmacology", 3, "A nurse is caring for a client receiving lithium for bipolar disorder. The nurse should monitor for toxicity if the serum level is:", ["0.6 mEq/L", "1.0 mEq/L", "Greater than 1.5 mEq/L", "0.8 mEq/L"], 2, "Lithium therapeutic range is 0.6-1.2 mEq/L. Levels >1.5 mEq/L indicate toxicity. Early toxicity signs: nausea, vomiting, diarrhea, fine hand tremor, drowsiness. Severe toxicity (>2.0 mEq/L): coarse tremor, ataxia, confusion, seizures, cardiac dysrhythmias. Maintain adequate fluid and sodium intake (dehydration and sodium depletion increase lithium levels). Options A, B, and D are within or near therapeutic range.", "Mood Stabilizers", "Lithium Monitoring", ["pharmacology", "lithium", "bipolar", "therapeutic-drug-monitoring"], "Lithium: therapeutic 0.6-1.2 mEq/L. Draw level 12 hours after last dose. Maintain adequate Na+ and fluid intake. NSAIDs and thiazide diuretics increase lithium levels. Monitor thyroid and renal function."),

  q("Pharmacology", 2, "A client is prescribed ciprofloxacin for a urinary tract infection. The nurse should advise the client to:", ["Take the medication with dairy products", "Avoid excessive sun exposure and report tendon pain immediately", "Take antacids concurrently for stomach protection", "Exercise vigorously during treatment"], 1, "Fluoroquinolones (ciprofloxacin, levofloxacin) cause photosensitivity (use sunscreen, avoid prolonged sun) and carry a black box warning for tendon rupture (especially Achilles tendon — more common in clients >60, concurrent corticosteroid use, or organ transplant recipients). Also avoid concurrent antacids/calcium/iron. Option A reduces absorption. Option C reduces absorption by chelation. Option D increases tendon rupture risk.", "Fluoroquinolones", "Patient Education", ["pharmacology", "fluoroquinolones", "ciprofloxacin", "adverse-effects"], "Fluoroquinolone black box warnings: tendon rupture, peripheral neuropathy, CNS effects. Avoid in children/adolescents (growth plate damage). Photosensitivity. Separate from antacids by 2 hours."),

  q("Pharmacology", 4, "A client is receiving a continuous IV nitroglycerin infusion. The nurse should use which type of tubing?", ["Standard PVC tubing", "Non-PVC (polyethylene) tubing because nitroglycerin adsorbs to PVC", "Any available tubing", "Tubing wrapped in aluminum foil"], 1, "Nitroglycerin is adsorbed by polyvinyl chloride (PVC) tubing, which can reduce drug delivery by 40-80%. Non-PVC (polyethylene) tubing must be used to ensure accurate dosing. Additionally, nitroglycerin should be prepared in glass bottles or non-PVC bags. Monitor blood pressure continuously. Option A would reduce drug delivery. Options C and D are not appropriate.", "Vasodilators", "Nitroglycerin Administration", ["pharmacology", "nitroglycerin", "IV-administration", "medication-safety"], "IV nitroglycerin: use non-PVC tubing and glass bottles. Adsorbs to PVC (reduces delivery 40-80%). Monitor BP continuously. Titrate for desired effect. SL nitroglycerin: 1 tab q5min x 3, then call 911."),

  q("Pharmacology", 3, "A nurse is teaching a client about warfarin therapy. Which statement by the client indicates a need for further teaching?", ["I will keep my INR appointments regularly", "I can take ibuprofen for my headaches while on warfarin", "I will wear a medical alert bracelet", "I will notify my dentist that I take this medication"], 1, "NSAIDs (ibuprofen, naproxen) are contraindicated with warfarin because they inhibit platelet function and can cause GI bleeding, significantly increasing hemorrhage risk. Acetaminophen is the recommended alternative for pain and fever. Options A, C, and D demonstrate correct understanding of warfarin therapy.", "Anticoagulant Therapy", "Warfarin Drug Interactions", ["pharmacology", "warfarin", "NSAIDs", "drug-interactions"], "Warfarin interactions: NSAIDs (increase bleeding), antibiotics (alter gut flora, change vitamin K), amiodarone (increases warfarin effect), grapefruit. Safe analgesic: acetaminophen (monitor liver)."),

  q("Pharmacology", 3, "A client receives naloxone (Narcan) for opioid overdose. The nurse should continue to monitor the client because:", ["Naloxone provides permanent opioid reversal", "Naloxone has a shorter duration of action than most opioids, and respiratory depression may recur", "The opioid effect is eliminated after one dose", "No further monitoring is needed after the client awakens"], 1, "Naloxone's duration of action is 30-90 minutes, while many opioids last 4-6 hours or longer. As naloxone wears off, respiratory depression can recur (renarcotization). Repeated doses or a continuous infusion may be needed. Monitor respiratory rate, oxygen saturation, and level of consciousness for at least 2 hours after the last naloxone dose. Option A is incorrect. Options C and D underestimate the risk.", "Opioid Antagonists", "Naloxone Monitoring", ["pharmacology", "naloxone", "opioid-reversal", "monitoring"], "Naloxone: onset 1-2 min IV, duration 30-90 min. Most opioids last longer = re-sedation risk. Monitor 2+ hours. May precipitate acute withdrawal in opioid-dependent patients. Can be given IV, IM, SQ, or intranasal."),

  q("Pharmacology", 2, "A nurse is preparing to administer enoxaparin (Lovenox) subcutaneously. The nurse should:", ["Aspirate before injection and massage the injection site afterward", "Inject into the abdomen, do not aspirate, and do not massage the site", "Administer in the deltoid muscle", "Flush the syringe after injection"], 1, "Low molecular weight heparin (LMWH) injection technique: inject subcutaneously into the abdomen (at least 2 inches from the umbilicus), alternating sides. Do NOT aspirate (may cause bruising). Do NOT massage the injection site (increases bruising and hematoma formation). Hold the skin fold during injection. The prefilled syringe should NOT have air expelled. Options A, C, and D are incorrect techniques.", "Anticoagulant Therapy", "LMWH Administration", ["pharmacology", "enoxaparin", "subcutaneous-injection", "technique"], "Enoxaparin: abdomen SC only, no aspiration, no massage, rotate sites, leave air bubble in syringe. Monitor platelets for HIT. No routine aPTT monitoring (monitor anti-Xa if needed)."),

  q("Pharmacology", 3, "A client is prescribed spironolactone for heart failure. The nurse should advise the client to avoid:", ["Bananas and oranges", "Potassium-rich foods and potassium supplements due to risk of hyperkalemia", "Dairy products", "All sodium-containing foods"], 1, "Spironolactone is a potassium-sparing diuretic and aldosterone antagonist. It inhibits sodium reabsorption and potassium excretion, causing potassium retention. Combined with potassium-rich foods or supplements, or with ACE inhibitors/ARBs, dangerous hyperkalemia can develop. Monitor serum potassium regularly. Options A lists specific potassium-rich foods but the answer should encompass all. Option C is unrelated. Option D — sodium restriction is separate guidance.", "Diuretics", "Potassium-Sparing Diuretics", ["pharmacology", "spironolactone", "hyperkalemia", "heart-failure"], "Potassium-sparing diuretics (spironolactone, amiloride, triamterene): risk of hyperkalemia. Avoid K+ supplements and salt substitutes (contain KCl). Monitor K+ especially with ACE inhibitors/ARBs."),

  q("Pharmacology", 3, "A client receiving IV magnesium sulfate for preeclampsia develops absent deep tendon reflexes. The nurse should:", ["Continue the infusion at the current rate", "Stop the infusion immediately and prepare to administer calcium gluconate", "Increase the infusion rate", "Administer IV oxytocin"], 1, "Loss of deep tendon reflexes (DTRs) is the earliest sign of magnesium toxicity. Normal therapeutic magnesium levels for preeclampsia are 4-7 mEq/L. Progression of toxicity: loss of DTRs (7-10 mEq/L) → respiratory depression (10-12 mEq/L) → cardiac arrest (>15 mEq/L). The antidote is IV calcium gluconate. The infusion must be stopped immediately. Option A risks further toxicity. Option C worsens toxicity. Option D is unrelated.", "Magnesium Sulfate", "Toxicity Recognition", ["pharmacology", "magnesium", "preeclampsia", "toxicity"], "MgSO4 monitoring: DTRs (absent = stop infusion), RR (< 12 = stop), UO (< 30 mL/hr = stop), LOC. Antidote: calcium gluconate 1g IV. Keep at bedside during MgSO4 infusion."),

  q("Pharmacology", 2, "A nurse is teaching a client about nitroglycerin sublingual tablets. Which instruction is correct?", ["Store in a plastic pill organizer for convenience", "Keep in the original dark glass container, replace every 6 months, and take up to 3 tablets 5 minutes apart for chest pain", "Swallow the tablet with water for faster absorption", "Take all three tablets at once if chest pain occurs"], 1, "Sublingual nitroglycerin instructions: store in original dark glass container (light degrades the medication), replace every 6 months, take 1 tablet SL every 5 minutes for up to 3 doses. If pain is not relieved after the first dose, call 911. A burning/tingling sensation under the tongue indicates potency. Sit or lie down before taking (causes hypotension). Option A degrades the medication. Option C is the wrong route. Option D is unsafe.", "Antianginal Agents", "Nitroglycerin Patient Education", ["pharmacology", "nitroglycerin", "chest-pain", "patient-education"], "SL NTG: 1 tab q5min x 3 max. Call 911 after first dose if not relieved. Store in dark glass. Burning/tingling = potent. Sit down before taking. Do NOT take with PDE5 inhibitors (sildenafil — severe hypotension)."),

  q("Pharmacology", 3, "A client with heart failure is receiving furosemide (Lasix). The nurse should monitor for:", ["Hyperkalemia", "Hypokalemia, hyponatremia, and ototoxicity", "Hyperglycemia only", "Weight gain"], 1, "Furosemide is a loop diuretic that causes significant potassium, sodium, calcium, and magnesium losses. Hypokalemia can cause dangerous cardiac dysrhythmias (especially with concurrent digoxin use). Ototoxicity (usually reversible) can occur with rapid IV administration or high doses. Monitor daily weights, I&O, electrolytes, and hearing. Option A — loop diuretics cause hypokalemia. Option C — glucose may increase but is not the primary concern. Option D — expect weight loss.", "Loop Diuretics", "Furosemide Monitoring", ["pharmacology", "furosemide", "diuretics", "electrolytes"], "Loop diuretics: lose K+, Na+, Ca2+, Mg2+. Monitor electrolytes, especially K+ (digoxin + hypokalemia = toxicity). Ototoxicity: administer slowly (IV push no faster than 20 mg/min). Sulfa allergy cross-reactivity possible."),

  q("Pharmacology", 3, "A client is prescribed prednisone for an autoimmune condition. The nurse should teach the client:", ["To stop the medication abruptly when symptoms resolve", "To taper the medication gradually and never stop abruptly due to risk of adrenal crisis", "That the medication has no significant side effects", "To take it on an empty stomach"], 1, "Long-term corticosteroid therapy suppresses the hypothalamic-pituitary-adrenal (HPA) axis. Abrupt discontinuation can cause adrenal crisis (hypotension, hypoglycemia, weakness, shock). The medication must be tapered gradually. Other teaching: take with food (GI irritation), monitor blood glucose (steroid-induced hyperglycemia), bone density screening (osteoporosis risk), infection prevention (immunosuppression), cushingoid effects. Option A is dangerous. Option C is incorrect. Option D increases GI upset.", "Corticosteroids", "Patient Education", ["pharmacology", "corticosteroids", "prednisone", "adrenal-suppression"], "Corticosteroid teaching: never stop abruptly (adrenal crisis), take with food, taper gradually, monitor glucose, report infections, carry steroid card. Long-term effects: osteoporosis, cataracts, Cushing's, adrenal suppression."),

  q("Pharmacology", 4, "A client is receiving amiodarone for ventricular tachycardia. The nurse should monitor for which organ-specific toxicities?", ["Nephrotoxicity only", "Pulmonary toxicity, thyroid dysfunction, hepatotoxicity, and corneal microdeposits", "Ototoxicity only", "Bone marrow suppression only"], 1, "Amiodarone has extensive organ toxicity profile: pulmonary toxicity (pneumonitis, fibrosis — baseline and periodic PFTs and chest X-rays), thyroid dysfunction (both hypo- and hyperthyroidism — amiodarone contains iodine), hepatotoxicity (monitor LFTs), corneal microdeposits (routine ophthalmologic exams), peripheral neuropathy, and photosensitivity (blue-gray skin discoloration). Options A, C, and D are incomplete.", "Antidysrhythmics", "Amiodarone Monitoring", ["pharmacology", "amiodarone", "toxicity", "multi-organ"], "Amiodarone monitoring: PFTs + CXR (pulmonary), TFTs (thyroid), LFTs (liver), eye exams (corneal deposits), skin assessment (photosensitivity, blue-gray discoloration). Half-life: 40-55 DAYS."),

  q("Pharmacology", 2, "A nurse is administering intravenous phenytoin (Dilantin). Which solution should be used as the diluent?", ["Dextrose 5% in water (D5W)", "Normal saline (0.9% NaCl)", "Lactated Ringer's", "Dextrose 5% in half-normal saline"], 1, "Phenytoin (Dilantin) is only compatible with normal saline. It precipitates when mixed with dextrose-containing solutions, forming crystals that can cause phlebitis and embolism. Administer at a maximum rate of 50 mg/min (25 mg/min in elderly or cardiac patients). Use an in-line filter. Monitor for cardiovascular collapse during rapid infusion. Options A, C, and D contain dextrose or are incompatible.", "Anticonvulsants", "IV Phenytoin Administration", ["pharmacology", "phenytoin", "IV-compatibility", "medication-safety"], "IV phenytoin: NS ONLY (precipitates in dextrose). Max rate 50 mg/min (25 mg/min in elderly). Use in-line filter. Monitor ECG and BP during infusion. Fosphenytoin is water-soluble alternative."),

  q("Pharmacology", 3, "A client taking selective serotonin reuptake inhibitors (SSRIs) is prescribed tramadol for pain. The nurse should alert the provider about the risk of:", ["Hyperglycemia", "Serotonin syndrome from combined serotonergic effects", "Hypothyroidism", "Respiratory alkalosis"], 1, "Serotonin syndrome occurs when two or more serotonergic medications are combined, causing excessive serotonin activity. Symptoms include mental status changes (agitation, confusion), autonomic instability (tachycardia, diaphoresis, hyperthermia), and neuromuscular abnormalities (myoclonus, rigidity, hyperreflexia). SSRIs + tramadol (which has serotonergic activity) is a high-risk combination. Treatment: discontinue offending agents, cyproheptadine, supportive care. Options A, C, and D are unrelated.", "Serotonergic Drugs", "Serotonin Syndrome", ["pharmacology", "serotonin-syndrome", "SSRI", "drug-interactions"], "Serotonin syndrome triad: mental status changes, autonomic instability, neuromuscular hyperactivity. Common combinations: SSRI + MAOI, SSRI + tramadol, SSRI + triptans. Treatment: cyproheptadine, stop medications."),

  q("Pharmacology", 3, "A client with tuberculosis asks why multiple medications are prescribed. The nurse should explain:", ["A single antibiotic is sufficient for TB treatment", "Multiple drugs prevent drug resistance and target different stages of the TB bacterial lifecycle", "Multiple medications are prescribed to treat different symptoms", "The additional medications are optional and can be stopped early"], 1, "TB bacteria can develop resistance rapidly when exposed to a single drug. Multidrug therapy (RIPE: Rifampin, Isoniazid, Pyrazinamide, Ethambutol) attacks the bacteria at different lifecycle stages, preventing resistance development. Treatment is directly observed therapy (DOT) for 6-9 months. Option A leads to resistant TB. Option C is incorrect — all drugs target TB bacteria. Option D leads to treatment failure and resistance.", "Anti-TB Medications", "Multidrug Rationale", ["pharmacology", "tuberculosis", "anti-TB", "drug-resistance"], "TB multidrug therapy prevents resistance. DOT (directly observed therapy) ensures compliance. Treatment: 2 months intensive (RIPE), then 4+ months continuation (RI). Monitor LFTs (isoniazid + pyrazinamide hepatotoxic)."),

  q("Pharmacology", 2, "A nurse is administering an intramuscular injection to an adult. The vastus lateralis site is preferred when:", ["The client requests this site", "The deltoid is too small or contraindicated, or for large-volume (>1 mL) injections", "Only for children", "For all IM injections regardless of volume"], 1, "The vastus lateralis (outer middle third of the thigh) accommodates larger volumes (up to 3-5 mL in adults) and is preferred when the deltoid is unsuitable. The deltoid handles up to 1 mL (some sources say 2 mL). The ventrogluteal site is the preferred site for most adult IM injections (up to 3 mL). The dorsogluteal site is no longer recommended due to sciatic nerve injury risk. Option A is not the clinical rationale. Option C is incorrect. Option D is too broad.", "IM Injection Technique", "Site Selection", ["pharmacology", "injection-technique", "IM", "medication-administration"], "IM site selection: Ventrogluteal preferred (most adults), deltoid (vaccines, <1-2 mL), vastus lateralis (infants, large volumes). Dorsogluteal: NOT recommended (sciatic nerve risk). Z-track for irritating meds."),

  q("Pharmacology", 3, "A client is prescribed clopidogrel (Plavix) after coronary stent placement. The nurse should teach:", ["The medication can be stopped after 2 weeks", "Take the medication as prescribed for at least 6-12 months; stopping early dramatically increases stent thrombosis risk", "This medication replaces all other cardiac medications", "Take aspirin instead of clopidogrel"], 1, "Dual antiplatelet therapy (DAPT) with aspirin AND clopidogrel is essential after coronary stent placement to prevent stent thrombosis. Duration depends on stent type: bare-metal stent (minimum 1 month), drug-eluting stent (minimum 6-12 months). Premature discontinuation is the leading cause of stent thrombosis, which has a 20-40% mortality rate. Option A is dangerously premature. Option C is incorrect. Option D — both are needed.", "Antiplatelet Therapy", "Dual Antiplatelet Therapy", ["pharmacology", "clopidogrel", "stent", "antiplatelet"], "Post-stent DAPT: aspirin + clopidogrel (Plavix) for 6-12 months minimum. Stopping early = stent thrombosis (mortality 20-40%). PPI interaction: omeprazole reduces clopidogrel efficacy (use pantoprazole instead)."),

  q("Pharmacology", 3, "A client on isoniazid (INH) therapy for tuberculosis should receive supplementation with:", ["Vitamin C", "Vitamin B6 (pyridoxine) to prevent peripheral neuropathy", "Vitamin D", "Iron supplements"], 1, "Isoniazid inhibits pyridoxine (vitamin B6) metabolism, causing peripheral neuropathy (numbness, tingling, burning in hands/feet). Pyridoxine 25-50 mg/day is given concurrently to prevent this. Higher risk groups include malnourished patients, alcoholics, diabetics, and HIV-positive patients. Also monitor hepatic function (INH is hepatotoxic). Option A does not prevent INH neuropathy. Option C is unrelated. Option D is not indicated.", "Anti-TB Medications", "Isoniazid Supplementation", ["pharmacology", "isoniazid", "vitamin-B6", "tuberculosis"], "Isoniazid: give pyridoxine (B6) to prevent peripheral neuropathy. Hepatotoxic — monitor LFTs monthly. Avoid alcohol. Teach to report: jaundice, dark urine, fatigue, nausea (hepatitis signs)."),

  q("Pharmacology", 3, "A client is receiving total parenteral nutrition (TPN). The current bag runs out, and a new bag is not available. The nurse should:", ["Discontinue the IV and wait for the new bag", "Hang dextrose 10% or 20% in water to prevent rebound hypoglycemia", "Infuse normal saline at the TPN rate", "Increase the rate of the remaining TPN to finish it faster"], 1, "TPN contains high concentrations of dextrose. The pancreas adjusts insulin production to match. Abrupt discontinuation causes rebound hypoglycemia because insulin levels remain elevated while dextrose delivery stops. Hanging D10W or D20W provides continued glucose delivery until the new TPN bag is available. Option A risks severe hypoglycemia. Option C does not provide glucose. Option D can cause hyperglycemia and electrolyte imbalances.", "TPN", "Emergency Management", ["pharmacology", "TPN", "hypoglycemia", "IV-therapy"], "TPN: never abruptly discontinue. If bag unavailable, hang D10W. When discontinuing planned, taper rate over 1-2 hours. Monitor blood glucose every 4-6 hours. Use dedicated central line lumen."),

  q("Pharmacology", 3, "A nurse is caring for a client prescribed albuterol (Ventolin) and beclomethasone (QVAR) inhalers. The nurse should teach the client to use:", ["Beclomethasone first, then albuterol", "Albuterol first (rescue bronchodilator), wait 5-15 minutes, then beclomethasone (corticosteroid)", "Both inhalers at the same time", "Only one inhaler per day"], 1, "Albuterol (SABA/rescue) should be used FIRST to open the airways (bronchodilation), then wait 5-15 minutes before using the corticosteroid inhaler (beclomethasone). This sequence allows the corticosteroid to penetrate deeper into the opened airways for maximum anti-inflammatory effect. Rinse mouth after corticosteroid inhaler to prevent oral candidiasis. Option A reverses the order. Options C and D are incorrect.", "Inhaler Therapy", "Sequential Inhaler Use", ["pharmacology", "inhalers", "asthma", "bronchodilator"], "Inhaler order: bronchodilator FIRST (opens airways), then corticosteroid (deeper penetration). Wait 5-15 min between. Rinse mouth after ICS (prevent thrush). MDI: shake, exhale, inhale slowly, hold breath 10 sec."),

  q("Pharmacology", 4, "A client is prescribed methotrexate and asks about alcohol consumption. The nurse should advise:", ["Moderate alcohol intake is acceptable", "Avoid alcohol completely because methotrexate is hepatotoxic, and alcohol synergistically increases liver damage risk", "Only drink beer, not spirits", "Alcohol is only restricted on days the medication is taken"], 1, "Methotrexate is hepatotoxic, and concurrent alcohol use significantly increases the risk of liver fibrosis and cirrhosis. Complete alcohol avoidance is recommended during methotrexate therapy. Liver function tests should be monitored regularly. Other methotrexate precautions: folic acid supplementation, adequate hydration, and strict contraception (teratogenic). Options A, C, and D underestimate the risk.", "Immunosuppressants", "Methotrexate and Alcohol", ["pharmacology", "methotrexate", "hepatotoxicity", "patient-education"], "Methotrexate + alcohol: absolutely contraindicated (synergistic hepatotoxicity). Monitor LFTs regularly. Give folic acid to reduce side effects. Category X — strict contraception for both men and women during and 3 months after."),

  q("Pharmacology", 2, "A nurse is preparing to administer NPH insulin. Which characteristic is correct?", ["It is clear in appearance", "It is cloudy in appearance and must be gently rolled (not shaken) before administration", "It can be given IV", "It has a rapid onset of action"], 1, "NPH (isophane) insulin is an intermediate-acting insulin that appears cloudy (suspension). It must be gently rolled between the palms (not shaken — creates air bubbles that alter dosing accuracy) to resuspend. Onset: 2-4 hours, peak: 4-10 hours, duration: 10-16 hours. Option A — only rapid-acting and regular insulin are clear. Option C — only regular insulin can be given IV. Option D — NPH is intermediate, not rapid.", "Insulin", "NPH Insulin", ["pharmacology", "insulin", "NPH", "medication-administration"], "Insulin appearance: Clear = rapid (lispro/aspart/glulisine), regular, and long-acting (glargine/detemir). Cloudy = NPH only. If mixing: draw clear (regular) FIRST, then cloudy (NPH). Remember: 'Clear before cloudy.'"),

  q("Pharmacology", 3, "A client receiving IV potassium replacement complains of burning and pain at the IV site. The nurse should:", ["Increase the infusion rate to finish quickly", "Slow the infusion rate and assess the IV site for infiltration", "Switch to a subcutaneous injection", "Ignore the complaint as this is expected"], 1, "IV potassium is irritating to veins and can cause phlebitis and tissue damage. If the client reports burning or pain, the nurse should slow the rate, assess the IV site for signs of infiltration (swelling, coolness, blanching) or phlebitis (redness, warmth, tenderness along the vein). If infiltration is suspected, stop the infusion, remove the IV, elevate the extremity, and apply warm compresses. Option A worsens irritation. Option C — KCl is not given SC. Option D ignores a potential complication.", "Electrolyte Replacement", "IV KCl Administration", ["pharmacology", "potassium", "IV-site-management", "phlebitis"], "IV KCl irritation: slow rate, assess site, consider diluting further. Central line preferred for concentrations >40 mEq/L. Peripheral max: 10-20 mEq/hr, concentration ≤ 40 mEq/L."),

  q("Pharmacology", 3, "A client is prescribed warfarin and asks about over-the-counter medications. The nurse should warn the client to avoid:", ["Acetaminophen at recommended doses", "Herbal supplements such as St. John's Wort and ginkgo biloba", "Topical hydrocortisone cream", "Saline nasal spray"], 1, "St. John's Wort induces CYP enzymes, DECREASING warfarin levels (risk of clotting). Ginkgo biloba, ginseng, garlic, and vitamin E have antiplatelet/anticoagulant properties, INCREASING bleeding risk with warfarin. Clients should consult their provider before taking any OTC medications or herbal supplements. Option A is generally safe at recommended doses. Options C and D do not interact with warfarin.", "Anticoagulant Therapy", "Herbal Interactions", ["pharmacology", "warfarin", "herbal-interactions", "patient-education"], "Warfarin herbal interactions: St. John's Wort (decreases effect), ginkgo/garlic/ginseng (increase bleeding). Cranberry may increase INR. Always ask about supplements at every visit."),

  q("Pharmacology", 3, "A client is receiving a dopamine infusion at 5 mcg/kg/min. At this dose, the nurse expects the primary effect to be:", ["Peripheral vasoconstriction", "Increased renal and mesenteric blood flow and mild cardiac stimulation", "Bronchodilation", "Sedation"], 1, "Dopamine effects are dose-dependent: Low dose (1-5 mcg/kg/min) = dopaminergic: renal and mesenteric vasodilation (increases urine output). Moderate dose (5-10 mcg/kg/min) = beta-1: increased contractility and heart rate. High dose (>10 mcg/kg/min) = alpha-1: peripheral vasoconstriction. At 5 mcg/kg/min, the primary effects are renal vasodilation with emerging beta-1 effects. Option A occurs at higher doses. Options C and D are not dopamine effects.", "Vasopressors", "Dopamine Dosing", ["pharmacology", "dopamine", "dose-response", "critical-care"], "Dopamine dose-response: Low (1-5) = renal/mesenteric vasodilation. Moderate (5-10) = beta-1 cardiac stimulation. High (>10) = alpha vasoconstriction. Extravasation: treat with phentolamine injection."),

  q("Pharmacology", 2, "A client is prescribed allopurinol for chronic gout. The nurse should teach the client to:", ["Take it only during acute gout attacks", "Increase fluid intake to at least 2-3 liters per day to prevent renal calculi", "Avoid all dairy products", "Take it on an empty stomach for better absorption"], 1, "Allopurinol inhibits xanthine oxidase, reducing uric acid production. Adequate hydration (2-3 L/day) is essential to prevent uric acid from precipitating in the kidneys and forming renal calculi. Allopurinol should NOT be started during an acute attack (can worsen it). Take with food to reduce GI upset. Monitor uric acid levels and hepatic function. Option A — it is for prevention, not acute treatment. Option C is unnecessary. Option D — take with food.", "Antigout Agents", "Allopurinol Education", ["pharmacology", "allopurinol", "gout", "renal-calculi"], "Allopurinol: do NOT start during acute attack. Increase fluids to 2-3 L/day. Take with food. Monitor LFTs and uric acid. May cause rash — stop immediately (risk of Stevens-Johnson syndrome)."),

  q("Pharmacology", 3, "A nurse is caring for a client who overdosed on acetaminophen. The antidote that should be administered is:", ["Flumazenil", "N-acetylcysteine (Mucomyst)", "Protamine sulfate", "Naloxone"], 1, "N-acetylcysteine (NAC) is the specific antidote for acetaminophen overdose. It replenishes hepatic glutathione stores and prevents toxic metabolite (NAPQI) from causing hepatocellular damage. Most effective when given within 8 hours of ingestion but can be beneficial up to 72 hours. Can be given orally or IV (IV has fewer GI side effects). Option A reverses benzodiazepines. Option C reverses heparin. Option D reverses opioids.", "Acetaminophen Toxicity", "Antidote", ["pharmacology", "acetaminophen", "overdose", "NAC"], "Acetaminophen max dose: 4g/day (2g/day in liver disease or alcohol use). Toxic dose: >150 mg/kg. NAC most effective within 8 hours. Check 4-hour serum level and plot on Rumack-Matthew nomogram."),

  q("Pharmacology", 3, "A nurse is teaching a client about the SSRI sertraline (Zoloft). The nurse should advise:", ["The medication works immediately", "Full therapeutic effect may take 4-6 weeks; do not stop abruptly due to discontinuation syndrome", "Take the medication only when feeling depressed", "Alcohol use is safe with this medication"], 1, "SSRIs require 4-6 weeks for full therapeutic effect. Clients should be informed to continue taking the medication even if they do not feel immediate improvement. Abrupt discontinuation can cause SSRI discontinuation syndrome (dizziness, nausea, irritability, electric shock sensations/'brain zaps', flu-like symptoms). Always taper gradually. Option A creates false expectations. Option C leads to inconsistent levels. Option D increases CNS depression.", "Antidepressants", "SSRI Education", ["pharmacology", "SSRI", "sertraline", "patient-education"], "SSRI teaching: 4-6 weeks for full effect, take daily (not PRN), never stop abruptly (taper), avoid alcohol, watch for serotonin syndrome if combining with other serotonergic drugs. Monitor for suicidal ideation in first weeks."),

  q("Pharmacology", 4, "A nurse is administering IV calcium gluconate. The nurse should monitor the client's ECG during administration because rapid infusion can cause:", ["Hyperglycemia", "Cardiac arrest from hypercalcemia", "Pulmonary edema", "Hepatic failure"], 1, "Rapid IV calcium administration can cause hypercalcemia, leading to cardiac toxicity: bradycardia, shortened QT interval, heart block, and cardiac arrest (especially in clients on digoxin — calcium potentiates digoxin toxicity). IV calcium should be administered slowly (not to exceed 0.7-1.5 mEq/min) with continuous cardiac monitoring. Option A is unrelated. Options C and D are not direct effects of IV calcium.", "Electrolyte Replacement", "IV Calcium Safety", ["pharmacology", "calcium", "IV-administration", "cardiac-monitoring"], "IV calcium: infuse slowly with ECG monitoring. Extravasation causes tissue necrosis. Incompatible with many drugs (flush line before/after). Calcium + digoxin = increased toxicity risk."),

  q("Pharmacology", 2, "A client asks why they need to take both a statin and ezetimibe for high cholesterol. The nurse explains:", ["Both medications work the same way", "The statin reduces cholesterol production in the liver while ezetimibe blocks cholesterol absorption in the intestine, providing complementary mechanisms", "Ezetimibe replaces the statin", "The combination is no more effective than a statin alone"], 1, "Statins inhibit HMG-CoA reductase, reducing hepatic cholesterol synthesis. Ezetimibe blocks the NPC1L1 receptor in the small intestine, reducing dietary and biliary cholesterol absorption. Together, they address both cholesterol production and absorption, providing greater LDL reduction than either alone. This combination is used when statins alone are insufficient or at maximum tolerated dose. Options A, C, and D are incorrect.", "Antilipemics", "Combination Therapy", ["pharmacology", "statins", "ezetimibe", "lipid-management"], "Cholesterol-lowering synergy: statins (block production) + ezetimibe (block absorption). Add-on therapy when statin alone is insufficient. PCSK9 inhibitors (evolocumab, alirocumab) for very high risk."),

  q("Pharmacology", 3, "A nurse is administering adenosine for supraventricular tachycardia (SVT). The nurse should:", ["Administer slowly over 5 minutes", "Administer as a rapid IV push over 1-2 seconds followed immediately by a 20 mL NS flush", "Give it intramuscularly", "Infuse over 30 minutes"], 1, "Adenosine has an extremely short half-life (less than 10 seconds). It must be given as a rapid IV push through a large-bore IV as close to the heart as possible (antecubital preferred), followed immediately by a 20 mL NS rapid flush using a three-way stopcock. Warn the client they may feel brief chest discomfort, flushing, or dyspnea. Record a continuous ECG strip. Options A and D — too slow for adenosine. Option C — not given IM.", "Antidysrhythmics", "Adenosine Administration", ["pharmacology", "adenosine", "SVT", "IV-push"], "Adenosine: rapid IV push (1-2 sec) + 20mL NS flush immediately. Half-life <10 sec. Use proximal IV site. Warn patient of brief chest pressure/dyspnea. Record ECG strip during administration."),

  q("Pharmacology", 3, "A client taking an MAOI (phenelzine) should be warned to avoid:", ["Fresh vegetables", "Tyramine-rich foods such as aged cheeses, smoked meats, red wine, and soy sauce due to risk of hypertensive crisis", "All carbohydrates", "Citrus fruits"], 1, "MAOIs inhibit monoamine oxidase, which normally metabolizes tyramine. When tyramine-rich foods are consumed, tyramine accumulates and triggers massive norepinephrine release, causing hypertensive crisis (severe headache, neck stiffness, palpitations, diaphoresis, potentially stroke). Tyramine-rich foods: aged cheeses, smoked/cured meats, red wine, beer, soy sauce, fermented foods. Options A, C, and D are safe with MAOIs.", "Antidepressants", "MAOI Diet Restrictions", ["pharmacology", "MAOI", "tyramine", "hypertensive-crisis"], "MAOI + tyramine = hypertensive crisis. Avoid: aged cheese, cured meats, red wine, beer, soy sauce, sauerkraut, fava beans. Crisis treatment: phentolamine IV (alpha-blocker). Carry food restriction card."),

  q("Pharmacology", 3, "A nurse is caring for a client prescribed clozapine for treatment-resistant schizophrenia. The most serious adverse effect requiring routine monitoring is:", ["Dry mouth", "Agranulocytosis requiring weekly to biweekly CBC monitoring", "Weight gain", "Sedation"], 1, "Clozapine is the gold standard for treatment-resistant schizophrenia but carries a risk of fatal agranulocytosis (1-2% incidence). The Clozapine REMS program requires mandatory blood monitoring: weekly CBC for the first 6 months, biweekly for 6-12 months, then monthly thereafter. If ANC drops below 1,500/mm3, the drug must be discontinued. Options A, C, and D are common but not the most serious effect.", "Antipsychotics", "Clozapine Monitoring", ["pharmacology", "clozapine", "agranulocytosis", "schizophrenia"], "Clozapine: REMS program mandatory. Weekly CBC x 6 months, biweekly x 6 months, then monthly. Stop if ANC < 1,500. Also monitor for: myocarditis, metabolic syndrome, seizures, sialorrhea."),

  q("Pharmacology", 2, "A client is prescribed levothyroxine for hypothyroidism. The nurse should teach:", ["Take it with breakfast for better absorption", "Take it in the morning on an empty stomach, 30-60 minutes before food, and separate from calcium and iron by 4 hours", "Take it at bedtime with a snack", "It can be taken at any time regardless of food"], 1, "Levothyroxine absorption is impaired by food, calcium, iron, and antacids. Taking it 30-60 minutes before breakfast on an empty stomach optimizes absorption. Calcium and iron supplements should be taken 4+ hours apart. Monitor TSH levels 6-8 weeks after dose changes. Teach consistent timing and reporting signs of over-replacement (tachycardia, weight loss, anxiety). Option A reduces absorption. Options C and D are not optimal.", "Thyroid Replacement", "Levothyroxine Administration", ["pharmacology", "levothyroxine", "hypothyroidism", "absorption"], "Levothyroxine: empty stomach, 30-60 min before food. Separate from calcium, iron, antacids by 4 hrs. Check TSH 6-8 weeks after dose change. Signs of over-replacement: tachycardia, weight loss, insomnia."),

  q("Pharmacology", 3, "A client is prescribed morphine for severe pain. The nurse should assess for the most serious adverse effect:", ["Constipation", "Respiratory depression", "Nausea", "Pruritus"], 1, "Respiratory depression is the most serious and potentially fatal adverse effect of opioid analgesics. The nurse should monitor respiratory rate, depth, and SpO2. Hold morphine and notify the provider if RR < 12/min. Naloxone (Narcan) should be readily available. Tolerance develops to most opioid side effects EXCEPT constipation. Option A is the most common but not the most serious. Options C and D are common but manageable.", "Opioid Analgesics", "Morphine Safety", ["pharmacology", "morphine", "respiratory-depression", "opioid-safety"], "Opioid monitoring priority: respiratory depression (hold if RR < 12). Keep naloxone at bedside. Tolerance develops to all effects EXCEPT constipation — always prescribe a bowel regimen. Assess pain using standardized scale."),

  q("Pharmacology", 3, "A client is being discharged on apixaban (Eliquis) for atrial fibrillation. The nurse should teach the client that the reversal agent for this medication is:", ["Vitamin K", "Andexanet alfa (Andexxa)", "Protamine sulfate", "Fresh frozen plasma alone"], 1, "Andexanet alfa (Andexxa) is the specific reversal agent for factor Xa inhibitors (apixaban, rivaroxaban). It is a recombinant modified factor Xa protein that acts as a decoy to bind the anticoagulant. Vitamin K reverses warfarin. Protamine reverses heparin. FFP provides clotting factors but is not the specific reversal agent. Idarucizumab reverses dabigatran.", "Anticoagulant Therapy", "DOAC Reversal", ["pharmacology", "DOAC", "apixaban", "reversal-agent"], "DOAC reversal: Andexanet alfa for apixaban/rivaroxaban. Idarucizumab (Praxbind) for dabigatran. If specific reversal unavailable: PCC (prothrombin complex concentrate), supportive care."),

  q("Pharmacology", 2, "A nurse is teaching a client newly prescribed amlodipine for hypertension. The nurse should advise:", ["Rise slowly from sitting or lying positions to prevent orthostatic hypotension", "Take the medication only during hypertensive episodes", "Stop the medication if blood pressure normalizes", "Restrict fluid intake while on this medication"], 0, "Calcium channel blockers like amlodipine cause vasodilation, which can result in orthostatic hypotension, especially when starting therapy. Teach clients to rise slowly, dangle legs before standing, and avoid sudden position changes. Other side effects include peripheral edema, headache, flushing, and dizziness. Option B — antihypertensives are taken daily. Option C — hypertension management is lifelong. Option D is not necessary.", "Calcium Channel Blockers", "Patient Education", ["pharmacology", "amlodipine", "hypertension", "orthostatic-hypotension"], "CCB side effects: peripheral edema (dihydropyridines like amlodipine), constipation (non-dihydropyridines like verapamil, diltiazem), flushing, headache. Monitor BP and HR before administration."),

  q("Pharmacology", 3, "A client is prescribed gentamicin and furosemide concurrently. The nurse should alert the provider because:", ["These medications are always given together safely", "Both are ototoxic, and concurrent use significantly increases the risk of irreversible hearing loss", "Furosemide reduces gentamicin's effectiveness", "Gentamicin neutralizes furosemide"], 1, "Both aminoglycosides (gentamicin) and loop diuretics (furosemide) are independently ototoxic. Concurrent use creates synergistic ototoxicity with significantly increased risk of irreversible hearing loss. The nurse should alert the provider so that alternative medications or closer monitoring can be implemented. Also both are nephrotoxic, compounding renal injury risk. Options A, C, and D are incorrect.", "Drug Interactions", "Ototoxicity Risk", ["pharmacology", "drug-interactions", "ototoxicity", "nephrotoxicity"], "Ototoxic + ototoxic = synergistic risk. Aminoglycosides + loop diuretics: avoid if possible. If necessary, monitor drug levels, hearing, and renal function closely. Nephrotoxic combinations also increase risk."),
];

async function main() {
  let inserted = 0;
  const batchSize = 50;
  for (let i = 0; i < QS.length; i += batchSize) {
    const batch = QS.slice(i, i + batchSize);
    const values: string[] = [];
    const params: any[] = [];
    let idx = 1;
    for (const item of batch) {
      values.push(`($${idx},$${idx+1},$${idx+2},$${idx+3},$${idx+4},$${idx+5}::jsonb,$${idx+6}::jsonb,$${idx+7},$${idx+8}::integer,$${idx+9},$${idx+10},$${idx+11},$${idx+12},$${idx+13},$${idx+14}::text[],$${idx+15})`);
      params.push(
        item.tier, item.exam, "multiple_choice", "published",
        item.stem, JSON.stringify(item.options), JSON.stringify([item.correct]),
        item.rationale, item.diff, item.bs, "BOTH", hash(item.stem),
        item.topic, item.subtopic, "{" + item.tags.join(",") + "}", item.clinicalPearl
      );
      idx += 16;
    }
    const sql = `INSERT INTO exam_questions (tier, exam, question_type, status, stem, options, correct_answer, rationale, difficulty, body_system, region_scope, stem_hash, topic, subtopic, tags, clinical_pearl)
                 SELECT v.* FROM (VALUES ${values.join(",")}) AS v(tier,exam,question_type,status,stem,options,correct_answer,rationale,difficulty,body_system,region_scope,stem_hash,topic,subtopic,tags,clinical_pearl)
                 WHERE NOT EXISTS (SELECT 1 FROM exam_questions e WHERE e.stem_hash = v.stem_hash)`;
    const result = await pool.query(sql, params);
    inserted += result.rowCount || 0;
    console.log(`[RN-MedSurg-Pharm] Batch ${Math.floor(i/batchSize)+1}: inserted ${result.rowCount || 0} questions`);
  }
  console.log(`\n[RN-MedSurg-Pharm] Total inserted: ${inserted}/${QS.length}`);
  const counts = await pool.query(`SELECT tier, count(*) as cnt FROM exam_questions WHERE status='published' GROUP BY tier ORDER BY tier`);
  counts.rows.forEach((r: any) => console.log(`  ${r.tier}: ${r.cnt}`));

  const bodySys = await pool.query(`SELECT body_system, count(*) as cnt FROM exam_questions WHERE tier='rn' AND status='published' GROUP BY body_system ORDER BY cnt DESC LIMIT 30`);
  console.log(`\nRN Body System Distribution:`);
  bodySys.rows.forEach((r: any) => console.log(`  ${r.body_system || '(null)'}: ${r.cnt}`));

  await pool.end();
}

main().catch(e => { console.error(e); process.exit(1); });
